// ── Feed ──
const PAGE_SIZE = 20

// ── @mention autocomplete ──────────────────────────────────────────────────
function useMention(friends) {
  const [query, setQuery] = useState(null) // null = closed
  const [selIdx, setSelIdx] = useState(0)
  const filtered = query !== null
    ? friends.filter(f => f.name?.toLowerCase().startsWith(query.toLowerCase()))
    : []

  const detect = useCallback((text, cursor) => {
    const before = text.slice(0, cursor)
    // Don't trigger inside a completed @[...] bracket
    if (/@\[[^\]]*$/.test(before)) { setQuery(null); return }
    const m = before.match(/@([^\s@\[]*)$/)
    if (m) { setQuery(m[1]); setSelIdx(0) } else setQuery(null)
  }, [])

  const close = useCallback(() => setQuery(null), [])

  const handleKey = useCallback((e, onInsert) => {
    if (query === null || !filtered.length) return false
    if (e.key === 'ArrowDown') { e.preventDefault(); setSelIdx(i => Math.min(i + 1, filtered.length - 1)); return true }
    if (e.key === 'ArrowUp')   { e.preventDefault(); setSelIdx(i => Math.max(i - 1, 0)); return true }
    if (e.key === 'Enter')     { e.preventDefault(); onInsert(filtered[selIdx]); return true }
    if (e.key === 'Escape')    { setQuery(null); return true }
    return false
  }, [query, filtered, selIdx])

  const buildText = useCallback((text, cursor, friend) => {
    const before = text.slice(0, cursor)
    const atIdx = before.lastIndexOf('@')
    const tag = `@[${friend.name}]`
    const newText = before.slice(0, atIdx) + tag + ' ' + text.slice(cursor)
    setQuery(null)
    return { text: newText, cursor: atIdx + tag.length + 1 }
  }, [])

  return { query, filtered, selIdx, detect, close, handleKey, buildText }
}

function MentionDropdown({ filtered, selIdx, onSelect }) {
  if (!filtered.length) return null
  return (
    <div className="p-mention-dropdown">
      {filtered.map((f, i) => (
        <div key={f.id}
          className={'p-mention-item' + (i === selIdx ? ' p-mention-item--sel' : '')}
          onMouseDown={e => { e.preventDefault(); onSelect(f) }}>
          <span className="p-mention-av" style={{ background: nameToColor(f.name) }}>
            {getInitials(f.name)}
          </span>
          <span className="p-mention-name">{f.name}</span>
        </div>
      ))}
    </div>
  )
}

// Renders text with mentions and linkified URLs; supports right-click link removal
// textObj: full {da, en, sv, …} object for feed comments — enables on-demand translation
function CommentText({ text, textObj, lang }) {
  const [removedUrls, setRemovedUrls] = useState(new Set())
  const [fetchedTranslation, setFetchedTranslation] = useState(null)
  const [showOriginal, setShowOriginal] = useState(false)

  useEffect(() => {
    if (!textObj) return
    const [origLang, origText] = getSourceEntry(textObj)
    if (!origLang || origLang === lang) return
    if (!DEEPL_SUPPORTED.has(origLang) || !DEEPL_SUPPORTED.has(lang)) return
    if (textObj[lang]) return
    setFetchedTranslation(null)
    let cancelled = false
    apiTranslateText(origText, origLang, lang)
      .then(res => { if (!cancelled && res?.translatedText) setFetchedTranslation(res.translatedText) })
      .catch(() => {})
    return () => { cancelled = true }
  }, [textObj, lang])

  const [originalLang, originalText] = getSourceEntry(textObj)
  const storedTranslation = textObj?.[lang]
  const canTranslate = !!originalLang && originalLang !== lang
    && DEEPL_SUPPORTED.has(originalLang) && DEEPL_SUPPORTED.has(lang)
  const displayText = showOriginal
    ? (originalText || text || '')
    : (storedTranslation || fetchedTranslation || text || '')
  const isTranslated = canTranslate && !showOriginal && (storedTranslation || fetchedTranslation)

  const uiT = canTranslate ? getTranslations(lang) : null
  const parts = linkifyText(displayText)
  return (
    <>
      {parts.map((p, i) => {
        if (p.t === 'url') {
          if (removedUrls.has(p.v)) return <span key={i}>{p.v}</span>
          return <LinkWithMenu key={i} href={p.v} lang={lang} onRemove={() => setRemovedUrls(prev => new Set([...prev, p.v]))} />
        }
        if (p.t === 'mention') return (
          <span key={i} style={{ display: 'inline-block', background: '#e8f5e9', color: '#2D6A4F', borderRadius: 6, padding: '1px 7px', fontSize: '0.92em', fontWeight: 600, lineHeight: 1.5 }}>
            {p.v}
          </span>
        )
        return <span key={i}>{p.v}</span>
      })}
      {isTranslated && (
        <button style={translationBtnStyle} onClick={() => setShowOriginal(true)}>
          {uiT.translatedShowOriginal}
        </button>
      )}
      {!isTranslated && canTranslate && showOriginal && (
        <button style={translationBtnStyle} onClick={() => setShowOriginal(false)}>
          {uiT.showTranslation}
        </button>
      )}
    </>
  )
}

