// ── Group Members Panel ──
function MembersModal({ t, lang, conv, currentUser, onClose, onRemove, onMuteMember }) {
  const isCreator = conv.createdBy === currentUser.id || conv.createdBy == null
  const [muteTarget, setMuteTarget] = useState(null) // participant object to mute
  const now = new Date()

  const muteOptions = [
    { label: t.mute1h, minutes: 60 },
    { label: t.mute8h, minutes: 480 },
    { label: t.mute24h, minutes: 1440 },
    { label: t.mute1w, minutes: 10080 },
    { label: t.muteOff, minutes: null },
  ]

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="p-msg-modal" style={{ maxWidth: 380 }} onClick={e => e.stopPropagation()}>
        <div className="p-msg-modal-header">
          <span>{t.membersTitle}</span>
          <button className="p-msg-modal-close" onClick={onClose}>✕</button>
        </div>

        {muteTarget ? (
          <>
            <div style={{ padding: '8px 16px 4px', fontSize: 13, color: '#555' }}>
              {t.muteMemberTitle} <strong>{(muteTarget.name || '').split(' ')[0]}</strong>
            </div>
            <div className="p-msg-modal-list">
              {muteOptions.map(o => (
                <button
                  key={o.label}
                  className="p-msg-modal-item mute-option"
                  onClick={() => { onMuteMember(muteTarget.id, o.minutes); setMuteTarget(null) }}
                >
                  {o.label}
                </button>
              ))}
              <button className="p-msg-modal-item" onClick={() => setMuteTarget(null)} style={{ color: '#888' }}>
                {t.cancel}
              </button>
            </div>
          </>
        ) : (
          <div className="p-msg-modal-list" style={{ maxHeight: 360, overflowY: 'auto' }}>
            {conv.participants.map(p => {
              const isMe = p.id === currentUser.id
              const isConvCreator = p.id === conv.createdBy
              const adminMuted = p.adminMutedUntil && new Date(p.adminMutedUntil) > now
              return (
                <div key={p.id} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '8px 16px' }}>
                  <div className="p-avatar-xs" style={{ background: nameToColor(p.name), flexShrink: 0 }}>
                    {getInitials(p.name)}
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 14, fontWeight: 500, display: 'flex', alignItems: 'center', gap: 6 }}>
                      {p.name}
                      {isConvCreator && (
                        <span style={{ fontSize: 11, color: '#52B788', fontWeight: 400 }}>{t.youAreCreator}</span>
                      )}
                    </div>
                    {adminMuted && (
                      <div style={{ fontSize: 11, color: '#e07b39' }}>{t.memberMuted}</div>
                    )}
                  </div>
                  {isCreator && !isMe && (
                    <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
                      <button
                        className="p-msg-modal-btn secondary"
                        style={{ padding: '3px 8px', fontSize: 12 }}
                        title={adminMuted ? t.unmuteMember : t.muteMember}
                        onClick={() => setMuteTarget(p)}
                      >
                        {adminMuted ? '🔔' : '🔇'}
                      </button>
                      <button
                        className="p-msg-modal-btn danger"
                        style={{ padding: '3px 8px', fontSize: 12 }}
                        title={t.removeMember}
                        onClick={() => {
                          if (window.confirm(`${t.removeMemberConfirm}\n${p.name}`)) onRemove(p.id)
                        }}
                      >
                        ✕
                      </button>
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        )}
      </div>
    </div>
  )
}

// ── Search ──
function SearchPage({ lang, t, mode, onNavigateToPost, onNavigateToConv, onNavigateToCompany }) {
  const [searchParams, setSearchParams] = useSearchParams()
  const query = searchParams.get('q') || ''
  const setQuery = (q) => setSearchParams(q ? { q } : {})
  const [results, setResults] = useState(null) // { posts, messages } | null
  const [companyMatches, setCompanyMatches] = useState([])
  const [loading, setLoading] = useState(false)
  const inputRef = useRef(null)

  useEffect(() => { inputRef.current?.focus() }, [])

  useEffect(() => {
    if (!query.trim() || query.trim().length < 2) { setResults(null); setCompanyMatches([]); return }
    setLoading(true)
    const timer = setTimeout(async () => {
      try {
        const [data, compData] = await Promise.all([
          apiSearch(query.trim()),
          csrfFetch(`/api/companies/all?q=${encodeURIComponent(query.trim())}`, { credentials: 'include' })
            .then(r => r.ok ? r.json() : { companies: [] }).catch(() => ({ companies: [] })),
        ])
        setResults(data || { posts: [], messages: [] })
        setCompanyMatches(compData.companies || [])
      } finally {
        setLoading(false)
      }
    }, 320)
    return () => { clearTimeout(timer); setLoading(false) }
  }, [query])

  // Highlight matching text in an excerpt
  const excerpt = (text, q) => {
    if (!text) return null
    const qi = text.toLowerCase().indexOf(q.toLowerCase())
    if (qi === -1) return <span>{text.slice(0, 120)}{text.length > 120 ? '…' : ''}</span>
    const start = Math.max(0, qi - 35)
    const end = Math.min(text.length, qi + q.length + 65)
    return (
      <>
        {start > 0 && '…'}
        {text.slice(start, qi)}
        <mark className="p-search-hl">{text.slice(qi, qi + q.length)}</mark>
        {text.slice(qi + q.length, end)}
        {end < text.length && '…'}
      </>
    )
  }

  const hasPosts = results?.posts?.length > 0
  const hasMessages = results?.messages?.length > 0
  const hasCompanies = companyMatches.length > 0
  const empty = results && !hasPosts && !hasMessages && !hasCompanies

  return (
    <div className="p-search-page">
      {/* Search bar */}
      <div className="p-search-bar">
        <span className="p-search-bar-icon">🔍</span>
        <input
          ref={inputRef}
          className="p-search-bar-input"
          type="text"
          placeholder={t.searchPlaceholder}
          value={query}
          onChange={e => setQuery(e.target.value)}
          autoComplete="off"
        />
        {query && <button className="p-search-bar-clear" onClick={() => { setQuery(''); setResults(null); setCompanyMatches([]) }}>✕</button>}
      </div>

      {/* States */}
      {!query && <p className="p-search-hint">{t.searchHint}</p>}
      {loading && <div className="p-search-status">{t.searching}</div>}
      {empty && !loading && (
        <div className="p-search-status">
          {`${t.noResultsForQuery}${query}"`}
        </div>
      )}

      {/* Company results (always shown if match, no API needed) */}
      {hasCompanies && (
        <div className="p-search-results" style={{ marginBottom: 8 }}>
          <section className="p-search-section">
            <h3 className="p-search-section-title">
              <span>🏢</span> {t.companies}
              <span className="p-search-count">{companyMatches.length}</span>
            </h3>
            {companyMatches.map(c => (
              <div key={c.id} className="p-search-result" onClick={() => onNavigateToCompany(c.id)}>
                <div className="p-search-result-top">
                  <div style={{ width: 28, height: 28, borderRadius: 6, background: c.color, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: 700, fontSize: 13, flexShrink: 0 }}>{c.name[0]}</div>
                  <span className="p-search-result-author">{c.name}</span>
                  <span className="p-search-result-time">{c.industry}</span>
                  <span className="p-search-result-arrow">→</span>
                </div>
                <div className="p-search-result-text" style={{ paddingLeft: 36, color: '#888' }}>
                  {c.tagline} · {c.followers} {t.companyFollowers}
                </div>
              </div>
            ))}
          </section>
        </div>
      )}

      {/* Results */}
      {(hasPosts || hasMessages) && (
        <div className="p-search-results">
          {hasPosts && (
            <section className="p-search-section">
              <h3 className="p-search-section-title">
                <span>📝</span> {t.searchPostsTitle}
                <span className="p-search-count">{results.posts.length}</span>
              </h3>
              {results.posts.map(post => (
                <div key={post.id} className="p-search-result" onClick={() => onNavigateToPost(post.id)}>
                  <div className="p-search-result-top">
                    <div className="p-avatar-xs" style={{ background: nameToColor(post.author), flexShrink: 0 }}>
                      {getInitials(post.author)}
                    </div>
                    <span className="p-search-result-author">{post.author}</span>
                    <span className="p-search-result-time">{post.time?.[lang]}</span>
                    <span className="p-search-result-arrow">→</span>
                  </div>
                  <div className="p-search-result-text">{excerpt(post.text?.[lang], query.trim())}</div>
                </div>
              ))}
            </section>
          )}
          {hasMessages && (
            <section className="p-search-section">
              <h3 className="p-search-section-title">
                <span>💬</span> {t.searchMessagesTitle}
                <span className="p-search-count">{results.messages.length}</span>
              </h3>
              {results.messages.map(msg => (
                <div key={msg.id} className="p-search-result" onClick={() => onNavigateToConv(msg.conversationId)}>
                  <div className="p-search-result-top">
                    <div className="p-avatar-xs" style={{ background: nameToColor(msg.convName), flexShrink: 0 }}>
                      {getInitials(msg.convName)}
                    </div>
                    <span className="p-search-result-author">{msg.convName}</span>
                    <span className="p-search-result-time">{msg.time}</span>
                    <span className="p-search-result-arrow">→</span>
                  </div>
                  <div className="p-search-result-text">
                    <span className="p-search-result-from">{msg.from}: </span>
                    {excerpt(msg.text?.[lang], query.trim())}
                  </div>
                </div>
              ))}
            </section>
          )}
        </div>
      )}
    </div>
  )
}

function MessagesPage({ lang, t, currentUser, mode, ssePayload }) {
  const convMatch = useMatch('/messages/:convId')
  const openConvId = convMatch?.params?.convId ? parseInt(convMatch.params.convId, 10) : null
  const [activeConv, setActiveConv] = useState(0)
  const [conversations, setConversations] = useState([])
  const [friends, setFriends] = useState([])
  const [newMsg, setNewMsg] = useState('')
  const [msgMedia, setMsgMedia] = useState([]) // [{url, type, mime, preview}]
  const [uploadingMedia, setUploadingMedia] = useState(false)
  const [loadingOlder, setLoadingOlder] = useState(false)
  const [modal, setModal] = useState(null) // null | 'new' | 'invite' | 'mute' | 'rename'
  const [showConvMenu, setShowConvMenu] = useState(false)
  const [deleteConvId, setDeleteConvId] = useState(null) // id to confirm delete
  const messagesEndRef = useRef(null)
  const msgInputRef = useRef(null)
  const msgBodyRef = useRef(null)
  const msgMention = useMention(friends)
  const topMsgSentinelRef = useRef(null)
  const menuRef = useRef(null)
  const [msgHintOpen, setMsgHintOpen] = useState(false)
  const msgHintCloseRef = useRef(null)
  const [editingMsg, setEditingMsg] = useState(null) // { id, text }
  const [reportingMsg, setReportingMsg] = useState(null) // msgId
  const [msgReportReason, setMsgReportReason] = useState('')
  const [msgReportDone, setMsgReportDone] = useState(false)
  const handleMsgHintClick = () => {
    setMsgHintOpen(v => {
      if (!v) {
        clearTimeout(msgHintCloseRef.current)
        msgHintCloseRef.current = setTimeout(() => setMsgHintOpen(false), 4000)
      }
      return !v
    })
  }

  useEffect(() => {
    apiFetchConversations().then(data => { if (data) setConversations(data) })
    apiFetchFriends().then(data => { if (data) setFriends(data) })
  }, []) // eslint-disable-line react-hooks/exhaustive-deps

  // Live updates: handle SSE message/read_receipt events forwarded from Platform's shared SSE
  useEffect(() => {
    if (!ssePayload) return
    if (ssePayload.type === 'message') {
      setConversations(prev => prev.map(c => {
        if (c.id !== ssePayload.convId) return c
        const msgs = [...c.messages, ssePayload.msg]
        return {
          ...c,
          messages: msgs.length > MSG_PAGE_SIZE ? msgs.slice(-MSG_PAGE_SIZE) : msgs,
          totalMessages: (c.totalMessages || c.messages.length) + 1,
          unread: (c.unread || 0) + 1,
        }
      }))
    } else if (ssePayload.type === 'read_receipt') {
      setConversations(prev => prev.map(c => {
        if (c.id !== ssePayload.convId) return c
        const existing = c.readReceipts || []
        const updated = existing.filter(r => r.userId !== ssePayload.userId)
        updated.push({ userId: ssePayload.userId, name: ssePayload.name, lastReadAt: ssePayload.lastReadAt })
        return { ...c, readReceipts: updated }
      }))
    }
  }, [ssePayload])

  // Open a specific conversation when navigated from elsewhere (search, contact seller, etc.)
  useEffect(() => {
    if (!openConvId) return
    const idx = conversations.findIndex(c => c.id === openConvId)
    if (idx >= 0) { setActiveConv(idx); return }
    // Conversation not in list yet (e.g. just created) — refetch and retry
    apiFetchConversations().then(data => {
      if (!data) return
      setConversations(data)
      const i = data.findIndex(c => c.id === openConvId)
      if (i >= 0) setActiveConv(i)
    })
  }, [openConvId]) // eslint-disable-line react-hooks/exhaustive-deps

  // Close conv menu on outside click
  useEffect(() => {
    if (!showConvMenu) return
    const handle = (e) => { if (menuRef.current && !menuRef.current.contains(e.target)) setShowConvMenu(false) }
    document.addEventListener('mousedown', handle)
    return () => document.removeEventListener('mousedown', handle)
  }, [showConvMenu])

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [conversations, activeConv])

  // Infinite scroll — load older messages at top
  useEffect(() => {
    const el = topMsgSentinelRef.current
    if (!el) return
    const conv = conversations[activeConv]
    if (!conv || conv.messages.length >= (conv.totalMessages || 0)) return
    const observer = new IntersectionObserver(async (entries) => {
      if (!entries[0].isIntersecting || loadingOlder) return
      setLoadingOlder(true)
      const prevScrollHeight = msgBodyRef.current?.scrollHeight || 0
      const data = await apiFetchOlderConversationMessages(conv.id, conv.messages.length, MSG_PAGE_SIZE)
      if (data?.messages?.length > 0) {
        setConversations(prev => prev.map((c, i) => {
          if (i !== activeConv) return c
          const combined = [...data.messages, ...c.messages]
          return { ...c, messages: combined.length > 40 ? combined.slice(0, 40) : combined }
        }))
        requestAnimationFrame(() => {
          if (msgBodyRef.current) {
            msgBodyRef.current.scrollTop = msgBodyRef.current.scrollHeight - prevScrollHeight
          }
        })
      }
      setLoadingOlder(false)
    }, { threshold: 0.1 })
    observer.observe(el)
    return () => observer.disconnect()
  }, [activeConv, conversations, loadingOlder])

  useEffect(() => {
    if (!newMsg && msgInputRef.current) {
      msgInputRef.current.style.height = 'auto'
    }
  }, [newMsg])

  const handleSend = useCallback(() => {
    const text = newMsg.trim()
    const media = msgMedia.length ? msgMedia.map(({ url, type, mime }) => ({ url, type, mime })) : null
    if (!text && !media) return
    const conv = conversations[activeConv]
    const now = new Date()
    const time = now.toLocaleTimeString(getLocale(lang), { hour: '2-digit', minute: '2-digit' })
    const tmpKey = `tmp_${now.getTime()}`
    setConversations(prev => prev.map((c, i) => {
      if (i !== activeConv) return c
      const msgs = [...c.messages, { _tmpKey: tmpKey, sender_id: currentUser.id, from: currentUser.name, text: { da: text, en: text }, media, time, createdAtRaw: now.toISOString() }]
      return { ...c, messages: msgs.length > MSG_PAGE_SIZE ? msgs.slice(-MSG_PAGE_SIZE) : msgs,
        totalMessages: (c.totalMessages || c.messages.length) + 1, unread: 0 }
    }))
    setNewMsg('')
    setMsgMedia([])
    if (conv?.id) {
      apiSendConversationMessage(conv.id, text, media).then(res => {
        if (res?.id) {
          setConversations(prev => prev.map(c => ({
            ...c,
            messages: c.messages.map(m => m._tmpKey === tmpKey ? { ...m, id: res.id, _tmpKey: undefined } : m)
          })))
        }
      }).catch(() => {})
    }
  }, [newMsg, msgMedia, activeConv, conversations, currentUser.name])

  const handleMediaFiles = useCallback(async (files) => {
    const allowed = Array.from(files).filter(f => f.type.startsWith('image/') || f.type.startsWith('video/'))
    if (!allowed.length) return
    setUploadingMedia(true)
    const results = await Promise.all(allowed.map(async f => {
      const preview = f.type.startsWith('image/') ? URL.createObjectURL(f) : null
      const uploaded = await apiUploadFile(f)
      if (!uploaded?.url) return null
      return { url: uploaded.url, type: uploaded.type, mime: uploaded.mime || f.type, preview }
    }))
    setMsgMedia(prev => [...prev, ...results.filter(Boolean)])
    setUploadingMedia(false)
  }, [])

  const selectConv = useCallback((i) => {
    setActiveConv(i)
    setShowConvMenu(false)
    setConversations(prev => {
      const conv = prev[i]
      if (conv?.unread > 0 && conv?.id) apiMarkConversationRead(conv.id).catch(() => {})
      return prev.map((c, j) => j === i ? { ...c, unread: 0 } : c)
    })
  }, [])

  const handleCreate = async (selectedIds, convName) => {
    setModal(null)
    const data = await apiCreateConversation(selectedIds, convName)
    if (data?.id) {
      // Refresh conversations
      const updated = await apiFetchConversations()
      if (updated) {
        setConversations(updated)
        const idx = updated.findIndex(c => c.id === data.id)
        setActiveConv(idx >= 0 ? idx : 0)
      }
    }
  }

  // Invite more people to the active conversation
  const handleInvite = async (selectedIds) => {
    setModal(null)
    const conv = conversations[activeConv]
    if (!conv) return
    await apiInviteToConversation(conv.id, selectedIds)
    const updated = await apiFetchConversations()
    if (updated) {
      setConversations(updated)
      const idx = updated.findIndex(c => c.id === conv.id)
      setActiveConv(idx >= 0 ? idx : 0)
    }
  }

  // Mute
  const handleMute = async (minutes) => {
    const conv = conversations[activeConv]
    if (!conv) return
    const result = await apiMuteConversation(conv.id, minutes)
    if (result) {
      setConversations(prev => prev.map((c, i) =>
        i === activeConv ? { ...c, mutedUntil: result.mutedUntil } : c))
    }
  }

  // Rename
  const handleRename = async (name) => {
    setModal(null)
    const conv = conversations[activeConv]
    if (!conv) return
    await apiRenameConversation(conv.id, name)
    setConversations(prev => prev.map((c, i) =>
      i === activeConv ? { ...c, name, convName: name } : c))
  }

  // Leave group
  const handleLeave = async () => {
    const conv = conversations[activeConv]
    if (!conv || !window.confirm(t.leaveConfirm)) return
    await apiLeaveConversation(conv.id)
    const updated = await apiFetchConversations()
    setConversations(updated || [])
    setActiveConv(0)
  }

  // Remove participant (creator only)
  const handleRemoveMember = async (userId) => {
    const conv = conversations[activeConv]
    if (!conv) return
    await apiRemoveConversationParticipant(conv.id, userId)
    setConversations(prev => prev.map((c, i) =>
      i === activeConv ? { ...c, participants: c.participants.filter(p => p.id !== userId) } : c))
  }

  // Admin-mute participant (creator only)
  const handleMuteMember = async (userId, minutes) => {
    const conv = conversations[activeConv]
    if (!conv) return
    const result = await apiMuteConversationParticipant(conv.id, userId, minutes)
    if (result) {
      setConversations(prev => prev.map((c, i) =>
        i === activeConv
          ? { ...c, participants: c.participants.map(p => p.id === userId ? { ...p, adminMutedUntil: result.adminMutedUntil } : p) }
          : c))
    }
  }

  const conv = conversations[activeConv]
  const isMuted = conv?.mutedUntil && new Date(conv.mutedUntil) > new Date()

  // Friends not yet in this conversation (for invite)
  const nonParticipants = friends.filter(f => !conv?.participants?.some(p => p.id === f.id))

  return (
    <div className="p-messages" onClick={() => showConvMenu && setShowConvMenu(false)}>
      {/* ── Sidebar ── */}
      <div className="p-msg-sidebar">
        <div className="p-msg-sidebar-header">
          <h3 className="p-msg-sidebar-title">{t.messagesTitle}</h3>
          <span className="p-msg-sidebar-title-icon" title={t.messagesTitle}>💬</span>
          <div className="p-msg-sidebar-actions">
            <button className="p-msg-icon-btn" title={t.newMessage} onClick={() => setModal('new')}>✏️</button>
          </div>
        </div>

        {conversations.length === 0 && (
          <div className="p-msg-empty-sidebar">{t.noConversationsYet}</div>
        )}

        {conversations.map((c, i) => {
          const lastMsg = c.messages[c.messages.length - 1]
          const cIsMuted = c.mutedUntil && new Date(c.mutedUntil) > new Date()
          return (
            <div key={c.id} id={`conv-${c.id}`} className="p-msg-thread-wrap">
              {deleteConvId === c.id && (
                <div className="p-msg-delete-confirm" onClick={e => e.stopPropagation()}>
                  <span>{`${t.deleteConvName}${c.name}${t.deleteConvNameSuffix}`}</span>
                  <button className="p-msg-delete-yes" onClick={async () => {
                    await apiLeaveConversation(deleteConvId)
                    setConversations(prev => prev.filter(x => x.id !== deleteConvId))
                    setDeleteConvId(null)
                    setActiveConv(0)
                  }}>
                    {t.adminModKeywordDelete}
                  </button>
                  <button className="p-msg-delete-no" onClick={() => setDeleteConvId(null)}>
                    {t.adminModKeywordCancel}
                  </button>
                </div>
              )}
            <div
              className={`p-msg-thread${i === activeConv ? ' active' : ''}`}
              onClick={() => selectConv(i)}
            >
              {/* Avatar: stacked for multi-participant, single for 1:1 */}
              {c.participants.length > 2 ? (
                <div className="p-msg-group-avatar">
                  {c.participants.slice(0, 2).map((p, pi) => (
                    <div key={p.id} className="p-msg-group-avatar-chip" style={{ background: nameToColor(p.name), zIndex: 2 - pi, marginLeft: pi > 0 ? -10 : 0 }}>
                      {getInitials(p.name)}
                    </div>
                  ))}
                </div>
              ) : (
                <div style={{ position: 'relative', flexShrink: 0 }}>
                  <div className="p-avatar-sm" style={{ background: nameToColor(c.name) }}>
                    {getInitials(c.name)}
                  </div>
                  {c.otherOnline && <div className="online-dot" style={{ position: 'absolute', bottom: 1, right: 1, width: 9, height: 9, borderRadius: '50%', background: '#22c55e', border: '2px solid var(--color-card, #fff)', zIndex: 1 }} />}
                </div>
              )}
              <div className="p-msg-thread-info">
                <div className="p-msg-thread-name">
                  <span>{c.name}</span>
                  <span className="p-msg-thread-badges">
                    {cIsMuted && <span className="p-msg-muted-icon" title={t.mutedLabel}>🔕</span>}
                    {c.unread > 0 && <span className="p-msg-badge" title={`${c.unread}${t.unreadMessages}`}>{c.unread}</span>}
                  </span>
                </div>
                <div className="p-msg-thread-preview">
                  {lastMsg ? `${c.participants.length > 2 ? (lastMsg.from || '').split(' ')[0] + ': ' : ''}${lastMsg.text[lang] ?? lastMsg.text.en ?? lastMsg.text.da ?? ''}`.slice(0, 42) : ''}
                </div>
              </div>
              <button
                className="p-msg-thread-delete"
                title={t.deleteChat}
                onClick={e => { e.stopPropagation(); setDeleteConvId(c.id) }}
              >🗑</button>
            </div>
            </div>
          )
        })}
      </div>

      {/* ── Main chat area ── */}
      {!conv ? (
        <div className="p-msg-main p-msg-main-empty">
          <div className="p-empty-state">{t.noMessages}</div>
        </div>
      ) : (
        <div className="p-msg-main">
          {/* Header */}
          <div className="p-msg-header">
            {conv.participants.length > 2 ? (
              <div className="p-msg-group-avatar" style={{ flexShrink: 0 }}>
                {conv.participants.slice(0, 2).map((p, pi) => (
                  <div key={p.id} className="p-msg-group-avatar-chip" style={{ background: nameToColor(p.name), zIndex: 2 - pi, marginLeft: pi > 0 ? -10 : 0, width: 32, height: 32, fontSize: 11 }}>
                    {getInitials(p.name)}
                  </div>
                ))}
              </div>
            ) : (
              <div className="p-avatar-sm" style={{ background: nameToColor(conv.name), flexShrink: 0 }}>
                {getInitials(conv.name)}
              </div>
            )}
            <div className="p-msg-header-info">
              <span className="p-msg-header-name">
                {conv.name}
                {isMuted && <span className="p-msg-muted-icon" title={t.mutedLabel} style={{ marginLeft: 6 }}>🔕</span>}
              </span>
              {conv.participants.length > 2 && (
                <span className="p-msg-header-sub">
                  {conv.participants.length} {t.participants}
                </span>
              )}
            </div>
            {/* Conversation menu */}
            <div ref={menuRef} style={{ position: 'relative', marginLeft: 'auto' }}>
              <button
                className="p-msg-icon-btn"
                title={t.convMenu}
                onClick={e => { e.stopPropagation(); setShowConvMenu(v => !v) }}
              >•••</button>
              {showConvMenu && (
                <ConvMenu
                  t={t}
                  lang={lang}
                  conv={conv}
                  onClose={() => setShowConvMenu(false)}
                  onInvite={() => setModal('invite')}
                  onMute={() => setModal('mute')}
                  onRename={() => setModal('rename')}
                  onLeave={handleLeave}
                  onShowMembers={() => setModal('members')}
                />
              )}
            </div>
          </div>

          {/* Messages */}
          <div className="p-msg-body" ref={msgBodyRef}>
            {conv.messages.length < (conv.totalMessages || 0) && (
              <div ref={topMsgSentinelRef} className="p-feed-sentinel">
                {loadingOlder && <div className="p-feed-loading">{t.loadingOlder}</div>}
              </div>
            )}
            {conv.messages.map((msg, i) => {
              const isMe = msg.sender_id === currentUser.id || msg.from === currentUser.name
              // Read receipt: track who has read up to this message
              const isLastMine = isMe && conv.messages.slice(i + 1).every(m => m.from !== currentUser.name)
              const readers = isMe && msg.createdAtRaw
                ? (conv.readReceipts || []).filter(r => r.lastReadAt && new Date(r.lastReadAt) >= new Date(msg.createdAtRaw))
                : []
              // Replied: someone else sent a message after this one
              const hasReplyAfter = isMe && conv.messages.slice(i + 1).some(m => m.from !== currentUser.name)
              const isEditing = editingMsg?.id && editingMsg.id === msg.id
              const isReporting = reportingMsg === msg.id
              return (
                <div key={i} className={`p-msg-bubble-row${isMe ? ' mine' : ''}`}>
                  {!isMe && (
                    <div className="p-avatar-xs" style={{ background: nameToColor(msg.from), flexShrink: 0 }}>
                      {getInitials(msg.from)}
                    </div>
                  )}
                  <div style={{ display: 'flex', flexDirection: 'column', alignItems: isMe ? 'flex-end' : 'flex-start', flex: 1 }}>
                    <div className={`p-msg-bubble${isMe ? ' mine' : ''}`} style={{ position: 'relative' }}>
                      {conv.participants.length > 2 && !isMe && (
                        <div className="p-msg-sender-name">{(msg.from || '').split(' ')[0]}</div>
                      )}
                      {isEditing ? (
                        <div style={{ display: 'flex', gap: 4, alignItems: 'flex-end' }}>
                          <textarea
                            autoFocus
                            rows={2}
                            style={{ flex: 1, padding: '5px 8px', borderRadius: 8, border: '1px solid #ddd', fontSize: 13, fontFamily: 'inherit', resize: 'none', minWidth: 160 }}
                            value={editingMsg.text}
                            onChange={e => setEditingMsg(m => ({ ...m, text: e.target.value }))}
                          />
                          <button onClick={async () => {
                            await apiEditMessage(msg.id, editingMsg.text)
                            setConversations(prev => prev.map(c => ({
                              ...c,
                              messages: c.messages.map(m => m.id === msg.id ? { ...m, text: { da: editingMsg.text, en: editingMsg.text } } : m)
                            })))
                            setEditingMsg(null)
                          }} style={{ padding: '4px 8px', borderRadius: 6, border: 'none', background: '#1877F2', color: '#fff', fontSize: 12, cursor: 'pointer' }}>✓</button>
                          <button onClick={() => setEditingMsg(null)} style={{ padding: '4px 8px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', color: '#666', fontSize: 12, cursor: 'pointer' }}>✕</button>
                        </div>
                      ) : (
                        msg.text[lang] && (
                          <div style={{ whiteSpace: 'pre-wrap' }}>{linkifyText(msg.text[lang]).map((p, pi) =>
                            p.t === 'url'
                              ? <a key={pi} href={p.v} target="_blank" rel="noopener noreferrer" className="post-link">{p.v}</a>
                              : p.t === 'mention'
                                ? <span key={pi} className="p-mention">{p.v}</span>
                                : <span key={pi}>{p.v}</span>
                          )}</div>
                        )
                      )}
                      {!isEditing && msg.media?.length > 0 && (
                        <div style={{ marginTop: msg.text[lang] ? 6 : 0, maxWidth: 260 }}>
                          <PostMedia media={msg.media} lang={lang} />
                        </div>
                      )}
                      <div className="p-msg-time">{msg.time}</div>
                    </div>
                    {/* Action buttons — only shown when message has a server ID */}
                    {msg.id && (
                      <div style={{ display: 'flex', gap: 3, marginTop: 2, opacity: 0.55 }}>
                        {isMe && (
                          <>
                            <button onClick={() => setEditingMsg({ id: msg.id, text: msg.text[lang] || '' })}
                              style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 11, padding: '0 3px', color: 'inherit' }} title={t.edit || 'Rediger'}>✏️</button>
                            <button onClick={async () => {
                              await apiDeleteMessage(msg.id)
                              setConversations(prev => prev.map(c => ({
                                ...c, messages: c.messages.filter(m => m.id !== msg.id)
                              })))
                            }} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 11, padding: '0 3px', color: 'inherit' }} title={t.delete || 'Slet'}>🗑️</button>
                          </>
                        )}
                        {!isMe && (
                          <button onClick={() => { setReportingMsg(msg.id); setMsgReportReason(''); setMsgReportDone(false) }}
                            style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 11, padding: '0 3px', color: 'inherit' }} title={t.report || 'Anmeld'}>⚑</button>
                        )}
                      </div>
                    )}
                    {isReporting && (
                      <div style={{ background: 'var(--card-bg,#fff)', border: '1px solid var(--border,#ddd)', borderRadius: 8, padding: '8px 10px', marginTop: 4, minWidth: 200 }}>
                        {msgReportDone ? (
                          <span style={{ color: '#22c55e', fontSize: 12 }}>✓ {t.reported || 'Anmeldt'}</span>
                        ) : (
                          <>
                            <select value={msgReportReason} onChange={e => setMsgReportReason(e.target.value)}
                              style={{ width: '100%', padding: '4px 8px', borderRadius: 6, border: '1px solid var(--border,#ddd)', fontSize: 12, marginBottom: 6 }}>
                              <option value="">{t.reportSelectReason || 'Vælg årsag...'}</option>
                              <option value="spam">{t.reportReasonSpam || 'Spam'}</option>
                              <option value="hate">{t.reportReasonHate || 'Hadefuldt'}</option>
                              <option value="harassment">{t.reportReasonHarassment || 'Chikane'}</option>
                              <option value="violence">{t.reportReasonViolence || 'Vold'}</option>
                              <option value="other">{t.reportReasonOther || 'Andet'}</option>
                            </select>
                            <div style={{ display: 'flex', gap: 6 }}>
                              <button disabled={!msgReportReason} onClick={async () => {
                                await apiReportContent('message', msg.id, msgReportReason)
                                setMsgReportDone(true)
                                setTimeout(() => setReportingMsg(null), 1500)
                              }} style={{ padding: '3px 10px', borderRadius: 6, border: 'none', background: msgReportReason ? '#ef4444' : '#ccc', color: '#fff', fontSize: 12, cursor: msgReportReason ? 'pointer' : 'default' }}>
                                {t.report || 'Anmeld'}
                              </button>
                              <button onClick={() => setReportingMsg(null)} style={{ padding: '3px 8px', borderRadius: 6, border: '1px solid var(--border,#ddd)', background: 'none', color: '#888', fontSize: 12, cursor: 'pointer' }}>✕</button>
                            </div>
                          </>
                        )}
                      </div>
                    )}
                    {/* Message status indicators */}
                    {isMe && (
                      <div style={{ display: 'flex', alignItems: 'center', gap: 3, marginTop: 2, marginRight: 2 }}>
                        {readers.length > 0 ? (
                          <>
                            {isLastMine && readers.slice(0, 3).map(r => (
                              <div key={r.userId} title={r.name} style={{ width: 14, height: 14, borderRadius: '50%', background: nameToColor(r.name), display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 8, color: '#fff', fontWeight: 700 }}>
                                {getInitials(r.name)[0]}
                              </div>
                            ))}
                            <span
                              title={t.msgStatusRead + ': ' + readers.map(r => r.name).join(', ')}
                              style={{ fontSize: 10, color: '#52B788', letterSpacing: '-1px' }}
                            >✓✓</span>
                          </>
                        ) : (
                          <span title={t.msgStatusSent} style={{ fontSize: 10, color: '#bbb' }}>✓</span>
                        )}
                        {hasReplyAfter && (
                          <span title={t.msgStatusReplied} style={{ fontSize: 11, color: '#b0b0b0', marginLeft: 1 }}>↩</span>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              )
            })}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-msg-input-row" style={{ flexDirection: 'column', gap: 0 }}>
            {/* Media preview strip */}
            {msgMedia.length > 0 && (
              <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', padding: '6px 8px 4px', borderBottom: '1px solid #f0f0f0' }}>
                {msgMedia.map((m, i) => (
                  <div key={i} style={{ position: 'relative', width: 56, height: 56, borderRadius: 6, overflow: 'hidden', border: '1px solid #ddd', flexShrink: 0 }}>
                    {m.type === 'image'
                      ? <img src={m.preview || m.url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
                      : <div style={{ width: '100%', height: '100%', background: '#1a1a2e', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20 }}>🎬</div>
                    }
                    <button onClick={() => setMsgMedia(prev => prev.filter((_, j) => j !== i))} style={{ position: 'absolute', top: 1, right: 1, width: 16, height: 16, borderRadius: '50%', background: 'rgba(0,0,0,0.6)', color: '#fff', border: 'none', cursor: 'pointer', fontSize: 10, lineHeight: 1, padding: 0 }}>×</button>
                  </div>
                ))}
                {uploadingMedia && <div style={{ width: 56, height: 56, borderRadius: 6, border: '1px dashed #ccc', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18 }}>⏳</div>}
              </div>
            )}
            <div style={{ display: 'flex', alignItems: 'flex-end', gap: 0, width: '100%' }}>
              <span className={`p-input-hint-wrap${msgHintOpen ? ' active' : ''}`}>
                <span className="p-input-hint-icon" data-egg-hints onClick={handleMsgHintClick}>?</span>
                <span className="p-input-hint-tooltip">{t.msgInputHint}</span>
              </span>
              {/* Attach button */}
              <div style={{ alignSelf: 'flex-end', marginBottom: 4 }}>
                <MediaPickerButton
                  lang={lang}
                  accept="image/*,video/*"
                  align="right"
                  onFiles={files => handleMediaFiles(files)}
                />
              </div>
              <div style={{ position: 'relative', flex: 1 }}>
                {msgMention.query !== null && (
                  <MentionDropdown
                    filtered={msgMention.filtered}
                    selIdx={msgMention.selIdx}
                    onSelect={f => {
                      const cursor = msgInputRef.current?.selectionStart ?? newMsg.length
                      const { text, cursor: nc } = msgMention.buildText(newMsg, cursor, f)
                      setNewMsg(text)
                      setTimeout(() => {
                        if (msgInputRef.current) {
                          msgInputRef.current.focus()
                          msgInputRef.current.setSelectionRange(nc, nc)
                        }
                      }, 0)
                    }}
                  />
                )}
                <textarea
                  ref={msgInputRef}
                  className="p-msg-input"
                  placeholder={t.typeMessage}
                  value={newMsg}
                  rows={1}
                  onChange={e => {
                    setNewMsg(e.target.value)
                    e.target.style.height = 'auto'
                    e.target.style.height = Math.min(e.target.scrollHeight, 120) + 'px'
                    msgMention.detect(e.target.value, e.target.selectionStart)
                  }}
                  onPaste={e => {
                    const files = Array.from(e.clipboardData?.items || [])
                      .filter(item => item.kind === 'file' && (item.type.startsWith('image/') || item.type.startsWith('video/')))
                      .map(item => item.getAsFile())
                      .filter(Boolean)
                    if (files.length) { e.preventDefault(); handleMediaFiles(files) }
                  }}
                  onKeyDown={e => {
                    if (msgMention.handleKey(e, f => {
                      const cursor = msgInputRef.current?.selectionStart ?? newMsg.length
                      const { text, cursor: nc } = msgMention.buildText(newMsg, cursor, f)
                      setNewMsg(text)
                      setTimeout(() => {
                        if (msgInputRef.current) {
                          msgInputRef.current.focus()
                          msgInputRef.current.setSelectionRange(nc, nc)
                        }
                      }, 0)
                    })) return
                    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend() }
                  }}
                  onBlur={() => setTimeout(() => msgMention.close(), 150)}
                />
              </div>
              <button className="p-send-btn" onClick={handleSend}>{t.send}</button>
            </div>
          </div>
        </div>
      )}

      {/* ── Modals ── */}
      {modal === 'new' && (
        <NewConvModal
          t={t}
          lang={lang}
          friends={friends}
          existingParticipantIds={[]}
          onClose={() => setModal(null)}
          onCreate={handleCreate}
        />
      )}
      {modal === 'invite' && conv && (
        <NewConvModal
          t={{ ...t, newConvTitle: t.inviteTitle, startConv: t.inviteBtn }}
          lang={lang}
          friends={nonParticipants}
          existingParticipantIds={conv.participants.map(p => p.id)}
          onClose={() => setModal(null)}
          onCreate={(ids) => handleInvite(ids)}
        />
      )}
      {modal === 'mute' && <MuteModal t={t} onClose={() => setModal(null)} onMute={handleMute} />}
      {modal === 'rename' && conv && (
        <RenameModal t={t} current={conv.convName} onClose={() => setModal(null)} onRename={handleRename} />
      )}
      {modal === 'members' && conv && (
        <MembersModal
          t={t}
          lang={lang}
          conv={conv}
          currentUser={currentUser}
          onClose={() => setModal(null)}
          onRemove={(userId) => { handleRemoveMember(userId) }}
          onMuteMember={(userId, minutes) => { handleMuteMember(userId, minutes) }}
        />
      )}
    </div>
  )
}

// ── Events ──
