function CVProfileSection({ lang, t, isOwn, userId }) {
  const [data, setData] = useState(null)
  const [cvPublic, setCvPublic] = useState(false)
  const [editExp, setEditExp] = useState(null)  // null | 'new' | entry obj
  const [editEdu, setEditEdu] = useState(null)
  const [showLangForm, setShowLangForm] = useState(false)
  const [saving, setSaving] = useState(false)
  const [saveMsg, setSaveMsg] = useState(null)

  // Experience form state
  const [expForm, setExpForm] = useState({})
  // Education form state
  const [eduForm, setEduForm] = useState({})
  // Language form state
  const [langName, setLangName] = useState('')
  const [langProf, setLangProf] = useState('conversational')

  useEffect(() => {
    const load = isOwn
      ? apiGetCVProfile()
      : apiGetPublicCVProfile(userId)
    load.then(d => {
      if (d) {
        setData(d)
        setCvPublic(!!d.profile?.cv_public)
      }
    }).catch(() => {})
  }, [isOwn, userId])

  const showSaved = (msg) => { setSaveMsg(msg); setTimeout(() => setSaveMsg(null), 2000) }

  const toggleVisibility = async () => {
    const next = !cvPublic
    setCvPublic(next)
    await apiSetCVVisibility(next)
  }

  const openEditExp = (entry) => {
    setExpForm(entry ? {
      company: entry.company || '', title: entry.title || '',
      start_date: entry.start_date ? entry.start_date.slice(0, 10) : '',
      end_date: entry.end_date ? entry.end_date.slice(0, 10) : '',
      is_current: !!entry.is_current, description: entry.description || '',
    } : { company: '', title: '', start_date: '', end_date: '', is_current: false, description: '' })
    setEditExp(entry || 'new')
  }

  const saveExp = async () => {
    setSaving(true)
    try {
      let updated
      if (editExp === 'new') {
        updated = await apiAddWorkExperience(expForm)
        if (updated?.id) setData(d => ({ ...d, experience: [...(d.experience || []), updated] }))
      } else {
        updated = await apiUpdateWorkExperience(editExp.id, expForm)
        if (updated?.id) setData(d => ({ ...d, experience: (d.experience || []).map(e => e.id === updated.id ? updated : e) }))
      }
      setEditExp(null); showSaved(t.cvSaved)
    } finally { setSaving(false) }
  }

  const deleteExp = async (id) => {
    await apiDeleteWorkExperience(id)
    setData(d => ({ ...d, experience: (d.experience || []).filter(e => e.id !== id) }))
    setEditExp(null)
  }

  const openEditEdu = (entry) => {
    setEduForm(entry ? {
      institution: entry.institution || '', degree: entry.degree || '',
      field: entry.field || '', start_year: entry.start_year || '',
      end_year: entry.end_year || '', description: entry.description || '',
    } : { institution: '', degree: '', field: '', start_year: '', end_year: '', description: '' })
    setEditEdu(entry || 'new')
  }

  const saveEdu = async () => {
    setSaving(true)
    try {
      let updated
      if (editEdu === 'new') {
        updated = await apiAddEducation(eduForm)
        if (updated?.id) setData(d => ({ ...d, education: [...(d.education || []), updated] }))
      } else {
        updated = await apiUpdateEducation(editEdu.id, eduForm)
        if (updated?.id) setData(d => ({ ...d, education: (d.education || []).map(e => e.id === updated.id ? updated : e) }))
      }
      setEditEdu(null); showSaved(t.cvSaved)
    } finally { setSaving(false) }
  }

  const deleteEdu = async (id) => {
    await apiDeleteEducation(id)
    setData(d => ({ ...d, education: (d.education || []).filter(e => e.id !== id) }))
    setEditEdu(null)
  }

  const saveLang = async () => {
    if (!langName.trim()) return
    const entry = await apiAddLanguage({ language: langName.trim(), proficiency: langProf })
    if (entry?.id) {
      setData(d => ({ ...d, languages: [...(d.languages || []), entry] }))
      setLangName(''); setShowLangForm(false)
    }
  }

  const updateLangProf = async (id, proficiency) => {
    await apiUpdateLanguage(id, proficiency)
    setData(d => ({ ...d, languages: (d.languages || []).map(l => l.id === id ? { ...l, proficiency } : l) }))
  }

  const deleteLang = async (id) => {
    await apiDeleteLanguage(id)
    setData(d => ({ ...d, languages: (d.languages || []).filter(l => l.id !== id) }))
  }

  const fS = { display: 'block', width: '100%', padding: '8px 10px', borderRadius: 7, border: '1px solid #ddd', fontSize: 13, boxSizing: 'border-box', fontFamily: 'inherit' }
  const lS = { fontSize: 12, fontWeight: 600, color: '#555', marginTop: 10, display: 'block' }
  const PROF_LEVELS = ['basic', 'conversational', 'professional', 'fluent', 'native']
  const profLabel = (p) => ({ basic: t.cvProfBasic, conversational: t.cvProfConversational, professional: t.cvProfProfessional, fluent: t.cvProfFluent, native: t.cvProfNative }[p] || p)

  const formatDateRange = (entry) => {
    const from = entry.start_date ? new Date(entry.start_date).toLocaleDateString(getLocale(lang), { year: 'numeric', month: 'short' }) : ''
    const to = entry.is_current ? t.cvPresent : (entry.end_date ? new Date(entry.end_date).toLocaleDateString(getLocale(lang), { year: 'numeric', month: 'short' }) : '')
    return [from, to].filter(Boolean).join(' – ')
  }

  if (!data && !isOwn) return null
  if (!data) return <div style={{ fontSize: 13, color: '#aaa', textAlign: 'center', padding: 20 }}>⏳</div>

  const hasContent = (data.experience?.length || data.education?.length || data.languages?.length)

  if (!isOwn && !hasContent) return null

  return (
    <div className="p-card" style={{ marginTop: 16, padding: '16px 20px' }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16, gap: 10, flexWrap: 'wrap' }}>
        <h3 style={{ margin: 0, fontSize: 15, fontWeight: 700 }}>💼 {t.cvProfile}</h3>
        {isOwn && (
          <label style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 12, cursor: 'pointer', color: cvPublic ? '#2D6A4F' : '#888' }}>
            <input type="checkbox" checked={cvPublic} onChange={toggleVisibility} style={{ cursor: 'pointer' }} />
            {cvPublic ? t.cvProfileVisibility : t.cvProfileHidden}
          </label>
        )}
      </div>

      {saveMsg && <div style={{ fontSize: 12, color: '#2D6A4F', marginBottom: 8 }}>✓ {saveMsg}</div>}

      {/* Work Experience */}
      <div style={{ marginBottom: 18 }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: '#333' }}>🏢 {t.cvWorkExperience}</div>
          {isOwn && (
            <button onClick={() => openEditExp(null)} style={{ fontSize: 12, padding: '4px 10px', borderRadius: 6, border: '1px solid #2D6A4F', background: '#fff', color: '#2D6A4F', cursor: 'pointer', fontWeight: 600 }}>
              + {t.cvAddExperience}
            </button>
          )}
        </div>
        {(data.experience || []).length === 0 && (
          <div style={{ fontSize: 12, color: '#aaa', fontStyle: 'italic' }}>
            {isOwn ? (t.noExperienceAddedYet) : ''}
          </div>
        )}
        {(data.experience || []).map(e => (
          <div key={e.id} style={{ marginBottom: 10, paddingBottom: 10, borderBottom: '1px solid #f5f5f5' }}>
            {editExp && editExp !== 'new' && editExp.id === e.id ? (
              <CVExpForm form={expForm} setForm={setExpForm} fS={fS} lS={lS} t={t} lang={lang}
                onSave={saveExp} onCancel={() => setEditExp(null)} onDelete={() => deleteExp(e.id)} saving={saving} isNew={false} />
            ) : (
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
                <div>
                  <div style={{ fontSize: 14, fontWeight: 700 }}>{e.title}</div>
                  <div style={{ fontSize: 13, color: '#555' }}>{e.company}</div>
                  <div style={{ fontSize: 12, color: '#999' }}>{formatDateRange(e)}</div>
                  {e.description && <div style={{ fontSize: 13, color: '#666', marginTop: 4, lineHeight: 1.5 }}>{e.description}</div>}
                </div>
                {isOwn && (
                  <button onClick={() => openEditExp(e)} style={{ fontSize: 12, padding: '3px 8px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', color: '#555', cursor: 'pointer', flexShrink: 0 }}>
                    ✏️
                  </button>
                )}
              </div>
            )}
          </div>
        ))}
        {editExp === 'new' && (
          <CVExpForm form={expForm} setForm={setExpForm} fS={fS} lS={lS} t={t} lang={lang}
            onSave={saveExp} onCancel={() => setEditExp(null)} saving={saving} isNew={true} />
        )}
      </div>

      {/* Education */}
      <div style={{ marginBottom: 18 }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: '#333' }}>🎓 {t.cvEducation}</div>
          {isOwn && (
            <button onClick={() => openEditEdu(null)} style={{ fontSize: 12, padding: '4px 10px', borderRadius: 6, border: '1px solid #2D6A4F', background: '#fff', color: '#2D6A4F', cursor: 'pointer', fontWeight: 600 }}>
              + {t.cvAddEducation}
            </button>
          )}
        </div>
        {(data.education || []).length === 0 && (
          <div style={{ fontSize: 12, color: '#aaa', fontStyle: 'italic' }}>
            {isOwn ? (t.noEducationAddedYet) : ''}
          </div>
        )}
        {(data.education || []).map(e => (
          <div key={e.id} style={{ marginBottom: 10, paddingBottom: 10, borderBottom: '1px solid #f5f5f5' }}>
            {editEdu && editEdu !== 'new' && editEdu.id === e.id ? (
              <CVEduForm form={eduForm} setForm={setEduForm} fS={fS} lS={lS} t={t}
                onSave={saveEdu} onCancel={() => setEditEdu(null)} onDelete={() => deleteEdu(e.id)} saving={saving} isNew={false} />
            ) : (
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
                <div>
                  <div style={{ fontSize: 14, fontWeight: 700 }}>{[e.degree, e.field].filter(Boolean).join(', ') || e.institution}</div>
                  {(e.degree || e.field) && <div style={{ fontSize: 13, color: '#555' }}>{e.institution}</div>}
                  <div style={{ fontSize: 12, color: '#999' }}>{[e.start_year, e.end_year].filter(Boolean).join('–')}</div>
                  {e.description && <div style={{ fontSize: 13, color: '#666', marginTop: 4, lineHeight: 1.5 }}>{e.description}</div>}
                </div>
                {isOwn && (
                  <button onClick={() => openEditEdu(e)} style={{ fontSize: 12, padding: '3px 8px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', color: '#555', cursor: 'pointer', flexShrink: 0 }}>
                    ✏️
                  </button>
                )}
              </div>
            )}
          </div>
        ))}
        {editEdu === 'new' && (
          <CVEduForm form={eduForm} setForm={setEduForm} fS={fS} lS={lS} t={t}
            onSave={saveEdu} onCancel={() => setEditEdu(null)} saving={saving} isNew={true} />
        )}
      </div>

      {/* Languages */}
      <div>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: '#333' }}>🌐 {t.cvLanguages}</div>
          {isOwn && !showLangForm && (
            <button onClick={() => setShowLangForm(true)} style={{ fontSize: 12, padding: '4px 10px', borderRadius: 6, border: '1px solid #2D6A4F', background: '#fff', color: '#2D6A4F', cursor: 'pointer', fontWeight: 600 }}>
              + {t.cvAddLanguage}
            </button>
          )}
        </div>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
          {(data.languages || []).map(l => (
            <div key={l.id} style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '5px 10px', borderRadius: 20, background: '#f5f5f5', fontSize: 12 }}>
              <span style={{ fontWeight: 600 }}>{l.language}</span>
              {isOwn ? (
                <select value={l.proficiency} onChange={e => updateLangProf(l.id, e.target.value)}
                  style={{ fontSize: 11, border: 'none', background: 'transparent', cursor: 'pointer', color: '#666', padding: '0 2px' }}>
                  {PROF_LEVELS.map(p => <option key={p} value={p}>{profLabel(p)}</option>)}
                </select>
              ) : (
                <span style={{ color: '#888' }}>· {profLabel(l.proficiency)}</span>
              )}
              {isOwn && (
                <button onClick={() => deleteLang(l.id)} style={{ border: 'none', background: 'none', cursor: 'pointer', color: '#aaa', padding: '0 2px', fontSize: 11 }}>✕</button>
              )}
            </div>
          ))}
        </div>
        {showLangForm && (
          <div style={{ marginTop: 10, display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
            <input
              list="cv-language-list"
              style={{ ...fS, width: 'auto', flex: 1, minWidth: 140 }}
              value={langName}
              onChange={e => setLangName(e.target.value)}
              placeholder={t.typeLanguage}
              autoFocus
              onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); saveLang() } }}
            />
            <datalist id="cv-language-list">
              {CV_LANGUAGES.map(l => <option key={l} value={l} />)}
            </datalist>
            <select style={{ ...fS, width: 'auto' }} value={langProf} onChange={e => setLangProf(e.target.value)}>
              {PROF_LEVELS.map(p => <option key={p} value={p}>{profLabel(p)}</option>)}
            </select>
            <button onClick={saveLang} style={{ padding: '8px 14px', borderRadius: 7, border: 'none', background: '#2D6A4F', color: '#fff', cursor: 'pointer', fontSize: 13, fontWeight: 600 }}>{t.cvSave}</button>
            <button onClick={() => { setShowLangForm(false); setLangName('') }} style={{ padding: '8px 10px', borderRadius: 7, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 13 }}>✕</button>
          </div>
        )}
      </div>
    </div>
  )
}

function CVExpForm({ form, setForm, fS, lS, t, lang, onSave, onCancel, onDelete, saving, isNew }) {
  return (
    <div style={{ background: '#fafafa', borderRadius: 8, padding: '10px 12px', border: '1px solid #eee', marginBottom: 4 }}>
      <label style={lS}>{t.cvJobTitle} <span className="req">*</span></label>
      <input style={fS} value={form.title || ''} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} placeholder={t.eGSeniorDesigner} autoFocus />
      <label style={lS}>{t.cvCompany} <span className="req">*</span></label>
      <input style={fS} value={form.company || ''} onChange={e => setForm(f => ({ ...f, company: e.target.value }))} placeholder={t.companyName} />
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
        <div>
          <label style={lS}>{t.cvStartDate}</label>
          <input style={fS} type="month" value={(form.start_date || '').slice(0, 7)} onChange={e => setForm(f => ({ ...f, start_date: e.target.value ? `${e.target.value}-01` : '' }))} />
        </div>
        <div>
          <label style={lS}>{t.cvEndDate}</label>
          <input style={fS} type="month" value={(form.end_date || '').slice(0, 7)} onChange={e => setForm(f => ({ ...f, end_date: e.target.value ? `${e.target.value}-01` : '' }))} disabled={!!form.is_current} />
        </div>
      </div>
      <label style={{ ...lS, display: 'flex', alignItems: 'center', gap: 6, cursor: 'pointer' }}>
        <input type="checkbox" checked={!!form.is_current} onChange={e => setForm(f => ({ ...f, is_current: e.target.checked, end_date: '' }))} />
        {t.cvCurrentPosition}
      </label>
      <label style={lS}>{t.cvDescription}</label>
      <textarea style={{ ...fS, minHeight: 60, resize: 'vertical' }} value={form.description || ''} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
      <div style={{ display: 'flex', gap: 8, marginTop: 10, justifyContent: 'flex-end' }}>
        {!isNew && onDelete && <button type="button" onClick={onDelete} style={{ padding: '6px 12px', borderRadius: 6, border: '1px solid #e74c3c', background: '#fff', color: '#e74c3c', cursor: 'pointer', fontSize: 12 }}>{t.cvDelete}</button>}
        <button type="button" onClick={onCancel} style={{ padding: '6px 12px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 12 }}>{t.cvCancel}</button>
        <button type="button" onClick={onSave} disabled={saving || !form.title?.trim() || !form.company?.trim()} style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: '#2D6A4F', color: '#fff', cursor: 'pointer', fontSize: 12, fontWeight: 700 }}>
          {saving ? '…' : t.cvSave}
        </button>
      </div>
    </div>
  )
}

function CVEduForm({ form, setForm, fS, lS, t, onSave, onCancel, onDelete, saving, isNew }) {
  return (
    <div style={{ background: '#fafafa', borderRadius: 8, padding: '10px 12px', border: '1px solid #eee', marginBottom: 4 }}>
      <label style={lS}>{t.cvInstitution} <span className="req">*</span></label>
      <input style={fS} value={form.institution || ''} onChange={e => setForm(f => ({ ...f, institution: e.target.value }))} autoFocus />
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
        <div>
          <label style={lS}>{t.cvDegree}</label>
          <input style={fS} value={form.degree || ''} onChange={e => setForm(f => ({ ...f, degree: e.target.value }))} />
        </div>
        <div>
          <label style={lS}>{t.cvField}</label>
          <input style={fS} value={form.field || ''} onChange={e => setForm(f => ({ ...f, field: e.target.value }))} />
        </div>
        <div>
          <label style={lS}>{t.cvStartYear}</label>
          <input style={fS} type="number" min="1950" max="2030" value={form.start_year || ''} onChange={e => setForm(f => ({ ...f, start_year: e.target.value ? Number(e.target.value) : '' }))} />
        </div>
        <div>
          <label style={lS}>{t.cvEndYear}</label>
          <input style={fS} type="number" min="1950" max="2030" value={form.end_year || ''} onChange={e => setForm(f => ({ ...f, end_year: e.target.value ? Number(e.target.value) : '' }))} />
        </div>
      </div>
      <label style={lS}>{t.cvDescription}</label>
      <textarea style={{ ...fS, minHeight: 60, resize: 'vertical' }} value={form.description || ''} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
      <div style={{ display: 'flex', gap: 8, marginTop: 10, justifyContent: 'flex-end' }}>
        {!isNew && onDelete && <button type="button" onClick={onDelete} style={{ padding: '6px 12px', borderRadius: 6, border: '1px solid #e74c3c', background: '#fff', color: '#e74c3c', cursor: 'pointer', fontSize: 12 }}>{t.cvDelete}</button>}
        <button type="button" onClick={onCancel} style={{ padding: '6px 12px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 12 }}>{t.cvCancel}</button>
        <button type="button" onClick={onSave} disabled={saving || !form.institution?.trim()} style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: '#2D6A4F', color: '#fff', cursor: 'pointer', fontSize: 12, fontWeight: 700 }}>
          {saving ? '…' : t.cvSave}
        </button>
      </div>
    </div>
  )
}

function JobApplyModal({ job, lang, t, onClose, currentUser }) {
  const [name, setName] = useState(currentUser?.name || '')
  const [email, setEmail] = useState(currentUser?.email || '')
  const [message, setMessage] = useState('')
  const [cvFile, setCvFile] = useState(null)
  const [letterFile, setLetterFile] = useState(null)
  const [submitting, setSubmitting] = useState(false)
  const [done, setDone] = useState(false)
  const [error, setError] = useState(null)
  // AI generation state
  const [aiTab, setAiTab] = useState(null) // null | 'cv' | 'letter'
  const [generatedCV, setGeneratedCV] = useState('')
  const [generatedLetter, setGeneratedLetter] = useState('')
  const [generating, setGenerating] = useState(false)
  const [genError, setGenError] = useState(null)
  const [copiedCV, setCopiedCV] = useState(false)
  const [copiedLetter, setCopiedLetter] = useState(false)
  const cvRef = useRef(null)
  const letterRef = useRef(null)

  const handleSubmit = async (e) => {
    e.preventDefault()
    if (!name.trim() || !email.trim()) return
    setSubmitting(true); setError(null)
    try {
      const res = await apiApplyToJobFull(job.id, { name, email, message }, cvFile, letterFile)
      if (res?.ok) { setDone(true) }
      else setError(t.somethingWentWrong)
    } catch (err) {
      setError(err.message === 'Already applied'
        ? (t.youHaveAlreadyAppliedForThisJob)
        : (t.somethingWentWrong))
    } finally { setSubmitting(false) }
  }

  const handleGenerate = async (type) => {
    setGenerating(true); setGenError(null)
    const data = await apiGenerateCV(job.id, type)
    setGenerating(false)
    if (!data?.hasProfile && !data?.cv && !data?.letter) {
      setGenError(t.jobGenerateError); return
    }
    if (type === 'cv' || type === 'both') setGeneratedCV(data.cv || '')
    if (type === 'letter' || type === 'both') setGeneratedLetter(data.letter || '')
    setAiTab(type === 'letter' ? 'letter' : 'cv')
  }

  const copyText = (text, which) => {
    navigator.clipboard.writeText(text).then(() => {
      if (which === 'cv') { setCopiedCV(true); setTimeout(() => setCopiedCV(false), 2000) }
      else { setCopiedLetter(true); setTimeout(() => setCopiedLetter(false), 2000) }
    })
  }

  const downloadText = (text, filename) => {
    const blob = new Blob([text], { type: 'text/plain;charset=utf-8' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a'); a.href = url; a.download = filename; a.click()
    URL.revokeObjectURL(url)
  }

  const attachGenerated = (text, which) => {
    const blob = new Blob([text], { type: 'text/plain;charset=utf-8' })
    const filename = which === 'cv' ? 'cv.txt' : 'application-letter.txt'
    const file = new File([blob], filename, { type: 'text/plain' })
    if (which === 'cv') setCvFile(file)
    else setLetterFile(file)
    setAiTab(null)
  }

  const fS = { display: 'block', width: '100%', padding: '8px 12px', borderRadius: 8, border: '1px solid #ddd', fontSize: 13, boxSizing: 'border-box', marginTop: 4, fontFamily: 'inherit' }
  const lS = { fontSize: 12, fontWeight: 600, color: '#555', marginTop: 12, display: 'block' }
  const btnS = { padding: '7px 14px', borderRadius: 8, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 12, fontWeight: 600, color: '#444' }

  return (
    <div className="modal-backdrop" style={{ alignItems: 'flex-start', padding: '40px 16px 16px' }} onClick={onClose}>
      <div className="p-msg-modal" style={{ maxWidth: 520, maxHeight: 'calc(100vh - 56px)', margin: '0 auto' }} onClick={e => e.stopPropagation()}>
        <div className="p-msg-modal-header" style={{ position: 'sticky', top: 0, background: '#fff', zIndex: 1 }}>
          <span>📝 {t.applyForPosition}</span>
          <button className="p-msg-modal-close" onClick={onClose}>✕</button>
        </div>
        {done ? (
          <div style={{ padding: '24px 20px', textAlign: 'center', overflowY: 'auto' }}>
            <div style={{ fontSize: 32, marginBottom: 12 }}>✅</div>
            <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 6 }}>
              {t.applicationSent}
            </div>
            <div style={{ fontSize: 13, color: '#666', marginBottom: 16 }}>
              {t.theCompanyWillReachOutIfYouAreAGoodMatch}
            </div>
            <button className="p-events-create-btn" onClick={onClose}>{t.analyticsInsightClose}</button>
          </div>
        ) : (
          <form onSubmit={handleSubmit} style={{ padding: '16px 20px', overflowY: 'auto', flex: 1, minHeight: 0 }}>
            <div style={{ fontSize: 13, color: '#555', marginBottom: 12 }}>
              <strong>{typeof job.title === 'string' ? job.title : (job.title?.da || '')}</strong>
              {' '}&middot;{' '}
              {job.company_name || job.companyName || ''}
            </div>

            <label style={lS}>{t.yourName} <span className="req">*</span></label>
            <input style={fS} value={name} onChange={e => setName(e.target.value)} required autoFocus />
            <label style={lS}>{t.emailLabel} <span className="req">*</span></label>
            <input style={fS} type="email" value={email} onChange={e => setEmail(e.target.value)} autoComplete="email" required />
            <label style={lS}>{t.shortMessage}</label>
            <textarea style={{ ...fS, minHeight: 70, resize: 'vertical' }} value={message} onChange={e => setMessage(e.target.value)} placeholder={t.tellABitAboutYourself} />

            {/* AI generation panel */}
            <div style={{ marginTop: 14, padding: '10px 12px', borderRadius: 8, background: '#F0FAF4', border: '1px solid #b7dfc8' }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: '#2D6A4F', marginBottom: 6 }}>✨ {t.jobAIGenerateTitle}</div>
              <div style={{ fontSize: 11, color: '#4a7c62', marginBottom: 8 }}>{t.jobAIGenerateHint}</div>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                <button type="button" style={{ ...btnS, borderColor: '#b7dfc8', background: aiTab === 'cv' ? '#2D6A4F' : '#fff', color: aiTab === 'cv' ? '#fff' : '#2D6A4F' }}
                  onClick={() => aiTab === 'cv' ? setAiTab(null) : handleGenerate('cv')} disabled={generating}>
                  {generating && aiTab !== 'letter' ? t.jobGenerating : `📄 ${t.jobBuildCVFromProfile}`}
                </button>
                <button type="button" style={{ ...btnS, borderColor: '#b7dfc8', background: aiTab === 'letter' ? '#2D6A4F' : '#fff', color: aiTab === 'letter' ? '#fff' : '#2D6A4F' }}
                  onClick={() => aiTab === 'letter' ? setAiTab(null) : handleGenerate('letter')} disabled={generating}>
                  {generating && aiTab === 'letter' ? t.jobGenerating : `✍️ ${t.jobGenerateLetter}`}
                </button>
              </div>
              {genError && <div style={{ fontSize: 12, color: '#c0392b', marginTop: 6 }}>{genError}</div>}
              {aiTab === 'cv' && generatedCV && (
                <div style={{ marginTop: 10 }}>
                  <textarea style={{ ...fS, marginTop: 0, minHeight: 140, fontFamily: 'monospace', fontSize: 11, background: '#fff' }}
                    value={generatedCV} onChange={e => setGeneratedCV(e.target.value)} />
                  <div style={{ display: 'flex', gap: 8, marginTop: 6, flexWrap: 'wrap' }}>
                    <button type="button" style={btnS} onClick={() => copyText(generatedCV, 'cv')}>{copiedCV ? `✓ ${t.jobCVCopied}` : t.jobCVCopy}</button>
                    <button type="button" style={btnS} onClick={() => downloadText(generatedCV, 'cv.txt')}>⬇ {t.jobCVDownload}</button>
                    <button type="button" style={{ ...btnS, background: '#2D6A4F', color: '#fff', borderColor: '#2D6A4F' }} onClick={() => attachGenerated(generatedCV, 'cv')}>
                      📎 {t.jobAttachGenerated} (CV)
                    </button>
                  </div>
                </div>
              )}
              {aiTab === 'letter' && generatedLetter && (
                <div style={{ marginTop: 10 }}>
                  <textarea style={{ ...fS, marginTop: 0, minHeight: 140, fontSize: 12, background: '#fff' }}
                    value={generatedLetter} onChange={e => setGeneratedLetter(e.target.value)} />
                  <div style={{ display: 'flex', gap: 8, marginTop: 6, flexWrap: 'wrap' }}>
                    <button type="button" style={btnS} onClick={() => copyText(generatedLetter, 'letter')}>{copiedLetter ? `✓ ${t.jobCVCopied}` : t.jobCVCopy}</button>
                    <button type="button" style={btnS} onClick={() => downloadText(generatedLetter, 'application-letter.txt')}>⬇ {t.jobCVDownload}</button>
                    <button type="button" style={{ ...btnS, background: '#2D6A4F', color: '#fff', borderColor: '#2D6A4F' }} onClick={() => attachGenerated(generatedLetter, 'letter')}>
                      📎 {t.jobAttachGenerated} ({t.letter})
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* CV file upload */}
            <label style={lS}>{t.cVOptional}</label>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input ref={cvRef} type="file" style={{ ...fS, padding: '6px 8px', flex: 1 }} accept=".pdf,.doc,.docx,.txt" onChange={e => setCvFile(e.target.files?.[0] || null)} />
              {cvFile && <span style={{ fontSize: 11, color: '#2D6A4F', whiteSpace: 'nowrap' }}>✓ {cvFile.name}</span>}
            </div>
            <div style={{ fontSize: 11, color: '#999', marginTop: 2 }}>{t.jobCVHint}</div>

            {/* Application letter upload */}
            <label style={lS}>{t.jobApplicationLetter}</label>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input ref={letterRef} type="file" style={{ ...fS, padding: '6px 8px', flex: 1 }} accept=".pdf,.doc,.docx,.txt" onChange={e => setLetterFile(e.target.files?.[0] || null)} />
              {letterFile && <span style={{ fontSize: 11, color: '#2D6A4F', whiteSpace: 'nowrap' }}>✓ {letterFile.name}</span>}
            </div>
            <div style={{ fontSize: 11, color: '#999', marginTop: 2 }}>{t.jobApplicationLetterHint}</div>

            {error && <div style={{ color: '#e74c3c', fontSize: 12, marginTop: 8 }}>{error}</div>}
            <div style={{ display: 'flex', gap: 10, marginTop: 16 }}>
              <button type="button" onClick={onClose} style={{ flex: 1, padding: 10, borderRadius: 8, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 13 }}>
                {t.adminModKeywordCancel}
              </button>
              <button type="submit" disabled={submitting || !name.trim() || !email.trim()} style={{ flex: 2, padding: 10, borderRadius: 8, border: 'none', background: '#2D6A4F', color: '#fff', cursor: 'pointer', fontSize: 13, fontWeight: 700 }}>
                {submitting ? '…' : (t.sendApplication)}
              </button>
            </div>
          </form>
        )}
      </div>
    </div>
  )
}

// ── Jobs ──
const JOB_TRACK_STATUSES = [
  { value: 'not_applied', color: '#888', bg: '#f5f5f5', key: 'jobTrackNotApplied' },
  { value: 'applied', color: '#1877F2', bg: '#EBF4FF', key: 'jobTrackApplied' },
  { value: 'interview', color: '#E07B39', bg: '#FFF3EB', key: 'jobTrackInterview' },
  { value: 'offer', color: '#7C3AED', bg: '#F3EEFF', key: 'jobTrackOffer' },
  { value: 'hired', color: '#2D6A4F', bg: '#F0FAF4', key: 'jobTrackHired' },
  { value: 'rejected', color: '#c0392b', bg: '#FFF0F0', key: 'jobTrackRejected' },
  { value: 'not_interested', color: '#aaa', bg: '#f9f9f9', key: 'jobTrackNotInterested' },
]

function JobCard({ job, t, lang, onSaveToggle, onTrackChange, currentUser, onShare, onViewCompany, onContactCompany }) {
  const [isSaved, setIsSaved] = useState(!!job.saved)
  const [trackStatus, setTrackStatus] = useState(job.track_status || null)
  const [showApplyModal, setShowApplyModal] = useState(false)
  const [showSharesModal, setShowSharesModal] = useState(false)
  const [sharedWithData, setSharedWithData] = useState(null)
  const [sharesLoading, setSharesLoading] = useState(false)
  const companyName = job.company_name || job.companyName || ''
  const companyColor = job.company_color || job.companyColor || '#1877F2'
  const title = typeof job.title === 'string' ? job.title : (job.title?.[lang] || job.title?.da || '')
  const desc = typeof job.description === 'string' ? job.description : (job.description?.[lang] || job.description?.da || '')
  const reqs = typeof job.requirements === 'string' ? job.requirements : (job.requirements?.[lang] || job.requirements?.da || '')
  const applyLink = job.apply_link || job.applyLink || ''
  const postedDate = job.created_at ? new Date(job.created_at).toLocaleDateString() : (job.postedDate || '')
  const typeLabels = { fulltime: t.jobTypeFullTime, parttime: t.jobTypePartTime, freelance: t.jobTypeFreelance, internship: t.jobTypeInternship }
  const trackInfo = JOB_TRACK_STATUSES.find(s => s.value === trackStatus)

  const toggleSave = () => {
    csrfFetch(`/api/jobs/${job.id}/save`, { method: 'POST', credentials: 'include' })
      .then(r => r.ok ? r.json() : null)
      .then(data => {
        if (!data) return
        setIsSaved(data.saved)
        onSaveToggle?.(job.id, data.saved)
      })
      .catch(() => {})
  }

  const handleTrack = (status) => {
    const newStatus = status || null
    apiTrackJob(job.id, newStatus).then(data => {
      if (!data) return
      setTrackStatus(newStatus)
      if (newStatus) setIsSaved(true)
      onTrackChange?.(job.id, newStatus)
    }).catch(() => {})
  }

  return (
    <div className="p-card p-job-card">
      <div style={{ display: 'flex', gap: 12, alignItems: 'flex-start' }}>
        <button
          onClick={() => onViewCompany?.(job.company_id)}
          style={{ width: 44, height: 44, borderRadius: 10, background: companyColor, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: 800, fontSize: 20, flexShrink: 0, border: 'none', cursor: 'pointer', padding: 0 }}
        >
          {companyName[0]}
        </button>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: 8, flexWrap: 'wrap' }}>
            <h3 style={{ margin: '0 0 2px', fontSize: 16, fontWeight: 700 }}>{title}</h3>
            <div style={{ display: 'flex', gap: 6, flexShrink: 0, flexWrap: 'wrap' }}>
              {trackInfo && (
                <span style={{ fontSize: 11, fontWeight: 700, padding: '3px 10px', borderRadius: 20, background: trackInfo.bg, color: trackInfo.color }}>
                  {t[trackInfo.key]}
                </span>
              )}
              {job.share_count > 0 && (
                <span style={{ fontSize: 11, fontWeight: 700, padding: '3px 10px', borderRadius: 20, background: '#E0F2FE', color: '#0369A1' }}>
                  🔗 {t.shared}
                </span>
              )}
            </div>
          </div>
          <div style={{ fontSize: 13, color: '#666', marginBottom: 6 }}>
            {companyName} · {job.location}
            {!!job.remote && <span style={{ marginLeft: 6, fontSize: 11, padding: '2px 8px', borderRadius: 20, background: '#F0FAF4', color: '#2D6A4F', fontWeight: 600 }}>{t.jobRemote}</span>}
          </div>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 10 }}>
            <span className="p-event-type-badge">{typeLabels[job.type] || job.type}</span>
            <span style={{ fontSize: 12, color: '#999' }}>{postedDate}</span>
          </div>
          {(job.salary_min || job.salary_max) && (
            <div style={{ fontSize: 13, color: '#2D6A4F', fontWeight: 600, marginBottom: 8 }}>
              💰 {job.salary_min ? job.salary_min.toLocaleString() : '?'} – {job.salary_max ? job.salary_max.toLocaleString() : '?'} {job.salary_currency || 'DKK'} / {job.salary_period === 'annual' ? (t.year) : (t.mo)}
            </div>
          )}
          <p style={{ fontSize: 13, color: '#555', lineHeight: 1.5, margin: '0 0 10px' }}>{desc.slice(0, 200)}{desc.length > 200 ? '…' : ''}</p>
          {reqs && (
            <details style={{ marginBottom: 12 }}>
              <summary style={{ fontSize: 13, color: '#2D6A4F', fontWeight: 600, cursor: 'pointer' }}>
                {t.jobRequirements}
              </summary>
              <pre style={{ fontSize: 12, color: '#555', whiteSpace: 'pre-wrap', marginTop: 8, fontFamily: 'inherit', lineHeight: 1.6 }}>{reqs}</pre>
            </details>
          )}
          {job.collective_agreement && (
            <div style={{ fontSize: 12, color: '#555', marginBottom: 6 }}>
              📋 {t.jobCollectiveAgreement}: <strong>{job.collective_agreement}</strong>
            </div>
          )}
          {job.deadline && (
            <div style={{ fontSize: 12, color: '#c0392b', fontWeight: 600, marginBottom: 8 }}>
              ⏳ {t.jobDeadline}: {new Date(job.deadline).toLocaleDateString(getLocale(lang), { day: 'numeric', month: 'long', year: 'numeric' })}
            </div>
          )}
          <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap', alignItems: 'center' }}>
            <button
              onClick={() => setShowApplyModal(true)}
              className="p-events-create-btn"
              style={{ padding: '8px 18px', fontSize: 13 }}
            >
              {t.jobApply}
            </button>
            <button
              onClick={() => onContactCompany?.(job.company_id || job.companyId)}
              style={{ padding: '8px 14px', borderRadius: 8, border: '1px solid #ddd', background: '#fff', color: '#555', fontWeight: 600, fontSize: 13, cursor: 'pointer' }}
            >
              💬 {t.jobContact}
            </button>
            {job.contact_email && (
              <a
                href={`mailto:${job.contact_email}`}
                style={{ padding: '8px 14px', borderRadius: 8, border: '1px solid #ddd', background: '#fff', color: '#555', fontWeight: 600, fontSize: 13, textDecoration: 'none', display: 'inline-block' }}
              >
                ✉️ {t.jobMailBtn}
              </a>
            )}
            {applyLink && applyLink.startsWith('http') && (
              <a
                href={applyLink}
                target="_blank"
                rel="noopener noreferrer"
                style={{ padding: '8px 14px', borderRadius: 8, border: '1px solid #ddd', background: '#fff', color: '#555', fontWeight: 600, fontSize: 13, textDecoration: 'none', display: 'inline-block' }}
              >
                🔗 {t.jobOfficialSite}
              </a>
            )}
            <button
              onClick={toggleSave}
              style={{ padding: '8px 14px', borderRadius: 8, border: `1px solid ${isSaved ? '#2D6A4F' : '#ddd'}`, background: isSaved ? '#F0FAF4' : '#fff', color: isSaved ? '#2D6A4F' : '#555', fontWeight: 600, fontSize: 13, cursor: 'pointer' }}
            >
              {isSaved ? `★ ${t.jobSaved}` : `☆ ${t.jobSave}`}
            </button>
            <button
              onClick={() => {
                if (job.share_count > 0) {
                  // Show shares modal
                  setSharesLoading(true)
                  setShowSharesModal(true)
                  apiGetJobSharedWith(job.id)
                    .then(data => {
                      setSharedWithData(data?.sharedWith || [])
                      setSharesLoading(false)
                    })
                    .catch(() => {
                      setSharesLoading(false)
                    })
                } else {
                  onShare?.(job.id)
                }
              }}
              style={{
                padding: '8px 14px',
                borderRadius: 8,
                border: `1px solid ${job.share_count > 0 ? '#2D6A4F' : '#ddd'}`,
                background: job.share_count > 0 ? '#F0FAF4' : '#f5f5f5',
                color: job.share_count > 0 ? '#2D6A4F' : '#555',
                fontWeight: 600,
                fontSize: 13,
                cursor: 'pointer'
              }}
            >
              {job.share_count > 0 ? `✓ 🔗 ${t.shared} (${job.share_count})` : `🔗 ${t.eventShareConfirm}`}
            </button>
          </div>
          {/* Personal tracking status */}
          <div style={{ marginTop: 10, display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ fontSize: 12, color: '#888', fontWeight: 600 }}>📋 {t.jobTrackStatus}:</span>
            <select
              value={trackStatus || ''}
              onChange={e => handleTrack(e.target.value || null)}
              style={{ fontSize: 12, padding: '4px 8px', borderRadius: 8, border: `1px solid ${trackInfo ? trackInfo.color : '#ddd'}`, background: trackInfo ? trackInfo.bg : '#fff', color: trackInfo ? trackInfo.color : '#666', cursor: 'pointer', fontFamily: 'inherit', fontWeight: trackInfo ? 700 : 400 }}
            >
              <option value="">{t.jobTrackNone}</option>
              {JOB_TRACK_STATUSES.map(s => (
                <option key={s.value} value={s.value}>{t[s.key]}</option>
              ))}
            </select>
          </div>
        </div>
      </div>
      {showApplyModal && <JobApplyModal job={job} lang={lang} t={t} onClose={() => setShowApplyModal(false)} currentUser={currentUser} />}

      {showSharesModal && (
        <div className="modal-backdrop" onClick={() => setShowSharesModal(false)}>
          <div className="p-card" onClick={e => e.stopPropagation()} style={{ padding: 24, maxWidth: 500, width: '90%', maxHeight: '70vh', overflowY: 'auto', borderRadius: 16 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
              <h3 style={{ margin: 0, fontSize: 17, fontWeight: 700 }}>
                {`${t.sharedPersonsPrefix}${job.share_count}${job.share_count === 1 ? t.sharedPersonsSuffix : t.sharedPersonsSuffixPlural}`}
              </h3>
              <button onClick={() => setShowSharesModal(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 18, color: '#888' }}>✕</button>
            </div>
            {sharesLoading ? (
              <div style={{ textAlign: 'center', color: '#888', padding: 20 }}>⏳</div>
            ) : !sharedWithData || sharedWithData.length === 0 ? (
              <div style={{ textAlign: 'center', color: '#888', padding: 20 }}>{t.noSharingData}</div>
            ) : (
              <div>
                <div style={{ fontSize: 12, color: '#888', marginBottom: 12, fontStyle: 'italic' }}>
                  {t.onlyProfilesWithPublicProfilesShown}
                </div>
                {sharedWithData.map(user => (
                  <div key={user.id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 0', borderBottom: '1px solid #f0f0f0' }}>
                    <div className="p-avatar-sm" style={{ background: nameToColor(user.name), flexShrink: 0, width: 40, height: 40, borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: 16, fontWeight: 700 }}>
                      {getInitials(user.name)}
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 700, fontSize: 14 }}>{user.name}</div>
                      {user.location && <div style={{ fontSize: 12, color: '#888' }}>{user.location}</div>}
                    </div>
                    <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
                      {user.cv_public && (
                        <a
                          href={`/@${user.handle}/cv`}
                          target="_blank"
                          rel="noopener noreferrer"
                          style={{ padding: '6px 12px', borderRadius: 6, border: '1px solid #1877F2', background: '#EBF4FF', color: '#1877F2', fontSize: 12, cursor: 'pointer', fontWeight: 600, textDecoration: 'none', display: 'inline-block' }}
                        >
                          📄 CV
                        </a>
                      )}
                      <a
                        href={`/@${user.handle}`}
                        target="_blank"
                        rel="noopener noreferrer"
                        style={{ padding: '6px 12px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', color: '#555', fontSize: 12, cursor: 'pointer', fontWeight: 600, textDecoration: 'none', display: 'inline-block' }}
                      >
                        👤 {t.profile}
                      </a>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  )
}

function JobsPage({ lang, t, currentUser, mode, onNavigate }) {
  const [searchParams, setSearchParams] = useSearchParams()
  const tab = searchParams.get('tab') || 'all'
  const filterType = searchParams.get('type') || ''
  const filterLocation = searchParams.get('location') || ''
  const filterKeyword = searchParams.get('q') || ''
  const setTab = (t) => setSearchParams(p => { const n = new URLSearchParams(p); t === 'all' ? n.delete('tab') : n.set('tab', t); return n })
  const setFilterType = (v) => setSearchParams(p => { const n = new URLSearchParams(p); v ? n.set('type', v) : n.delete('type'); return n })
  const setFilterLocation = (v) => setSearchParams(p => { const n = new URLSearchParams(p); v ? n.set('location', v) : n.delete('location'); return n })
  const setFilterKeyword = (v) => setSearchParams(p => { const n = new URLSearchParams(p); v ? n.set('q', v) : n.delete('q'); return n })
  const [jobs, setJobs] = useState([])
  const [savedJobs, setSavedJobs] = useState([])
  const [trackedJobs, setTrackedJobs] = useState([])
  const [sharedJobs, setSharedJobs] = useState([])
  const [myJobs, setMyJobs] = useState([])
  const [loading, setLoading] = useState(true)
  const [showCreate, setShowCreate] = useState(false)
  const [editJob, setEditJob] = useState(null)
  const [myCompanies, setMyCompanies] = useState([])
  const [applicantsJob, setApplicantsJob] = useState(null) // job being viewed for applicants
  const [applicants, setApplicants] = useState([])
  const [applicantsLoading, setApplicantsLoading] = useState(false)
  const [shareJobId, setShareJobId] = useState(null) // job being shared
  const [shareQuery, setShareQuery] = useState('') // search term for users to share with
  const [shareUsers, setShareUsers] = useState([]) // search results
  const [sharedWithUsers, setSharedWithUsers] = useState([]) // users job is already shared with
  const [sharingSending, setShareSending] = useState(false)
  const [contactCompanyLead, setContactCompanyLead] = useState(null) // company being contacted

  useEffect(() => {
    const params = new URLSearchParams()
    if (filterKeyword) params.set('q', filterKeyword)
    if (filterType) params.set('type', filterType)
    setLoading(true)
    csrfFetch(`/api/jobs?${params}`, { credentials: 'include' })
      .then(r => r.ok ? r.json() : null)
      .then(data => { setJobs(data?.jobs || []); setLoading(false) })
      .catch(() => setLoading(false))
  }, [filterKeyword, filterType])

  useEffect(() => {
    if (tab === 'saved') {
      csrfFetch('/api/jobs/saved', { credentials: 'include' })
        .then(r => r.ok ? r.json() : null)
        .then(data => setSavedJobs(data?.jobs || []))
        .catch(() => {})
    }
    if (tab === 'tracking') {
      apiGetTrackedJobs().then(data => setTrackedJobs(data?.jobs || [])).catch(() => {})
    }
    if (tab === 'shared') {
      apiGetSharedJobs().then(data => setSharedJobs(data?.jobs || [])).catch(() => {})
    }
  }, [tab])

  useEffect(() => {
    csrfFetch('/api/companies', { credentials: 'include' })
      .then(r => r.ok ? r.json() : null)
      .then(data => setMyCompanies((data?.companies || []).filter(c => c.member_role === 'owner' || c.member_role === 'admin')))
      .catch(() => {})
  }, [])

  useEffect(() => {
    if (mode === 'business') {
      apiGetMyJobs().then(data => setMyJobs(data?.jobs || []))
    }
  }, [mode])

  useEffect(() => {
    if (shareJobId) {
      apiGetJobSharedWith(shareJobId).then(data => setSharedWithUsers(data?.sharedWith || [])).catch(() => {})
    }
  }, [shareJobId])

  const refreshMyJobs = () => apiGetMyJobs().then(data => setMyJobs(data?.jobs || []))

  const openApplicants = (job) => {
    setApplicantsJob(job)
    setApplicantsLoading(true)
    apiGetJobApplications(job.id).then(data => {
      setApplicants(data?.applications || [])
      setApplicantsLoading(false)
    }).catch(() => setApplicantsLoading(false))
  }

  const handleToggleActive = (job) => {
    csrfFetch(`/api/jobs/${job.id}`, {
      method: 'PUT', credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...job, active: !job.active }),
    })
      .then(r => r.ok ? r.json() : null)
      .then(data => { if (data) refreshMyJobs() })
      .catch(() => {})
  }

  const displayJobs = tab === 'saved' ? savedJobs : tab === 'tracking' ? trackedJobs : tab === 'shared' ? sharedJobs : jobs.filter(j => {
    if (filterLocation && !j.location?.toLowerCase().includes(filterLocation.toLowerCase()) && !j.remote) return false
    return true
  })

  const typeLabels = { fulltime: t.jobTypeFullTime, parttime: t.jobTypePartTime, freelance: t.jobTypeFreelance, internship: t.jobTypeInternship }

  return (
    <div className="p-events" style={{ maxWidth: 720 }}>
      <div className="p-events-header">
        <h2 className="p-section-title" style={{ margin: 0 }}>💼 {t.jobsTitle}</h2>
        {mode === 'business' && (
          <button className="p-events-create-btn" onClick={() => setShowCreate(true)}>
            + {t.createJob}
          </button>
        )}
      </div>

      {/* Filters — only shown on browse tabs */}
      {tab !== 'mine' && tab !== 'tracking' && (
        <div className="p-card" style={{ marginBottom: 14, display: 'flex', gap: 10, flexWrap: 'wrap' }}>
          <input
            className="p-search-input"
            style={{ flex: 2, minWidth: 120 }}
            placeholder={t.jobSearchKeyword}
            value={filterKeyword}
            onChange={e => setFilterKeyword(e.target.value)}
          />
          <input
            className="p-search-input"
            style={{ flex: 1, minWidth: 100 }}
            placeholder={t.jobSearchLocation}
            value={filterLocation}
            onChange={e => setFilterLocation(e.target.value)}
          />
          <select
            style={{ padding: '8px 12px', borderRadius: 8, border: '1px solid #ddd', fontSize: 13, fontFamily: 'inherit', color: '#444' }}
            value={filterType}
            onChange={e => setFilterType(e.target.value)}
          >
            <option value="">{t.jobSearchType}</option>
            <option value="fulltime">{t.jobTypeFullTime}</option>
            <option value="parttime">{t.jobTypePartTime}</option>
            <option value="freelance">{t.jobTypeFreelance}</option>
            <option value="internship">{t.jobTypeInternship}</option>
          </select>
        </div>
      )}

      <div className="p-filter-tabs" style={{ marginBottom: 16 }}>
        <button className={`p-filter-tab${tab === 'all' ? ' active' : ''}`} onClick={() => setTab('all')}>
          {t.allJobs} ({jobs.length})
        </button>
        <button className={`p-filter-tab${tab === 'saved' ? ' active' : ''}`} onClick={() => setTab('saved')}>
          {t.savedJobs} ({savedJobs.length})
        </button>
        <button className={`p-filter-tab${tab === 'tracking' ? ' active' : ''}`} onClick={() => setTab('tracking')}>
          {t.jobTrackTab} ({trackedJobs.length})
        </button>
        <button className={`p-filter-tab${tab === 'shared' ? ' active' : ''}`} onClick={() => setTab('shared')}>
          {t.sharedWithMe} ({sharedJobs.length})
        </button>
        {mode === 'business' && (
          <button className={`p-filter-tab${tab === 'mine' ? ' active' : ''}`} onClick={() => setTab('mine')}>
            {t.jobMyListings} ({myJobs.length})
          </button>
        )}
        <button className={`p-filter-tab${tab === 'alerts' ? ' active' : ''}`} onClick={() => setTab('alerts')}>
          🔔 {t.alerts}
        </button>
      </div>

      {/* Job Alerts tab */}
      {tab === 'alerts' && (
        <div className="p-card" style={{ padding: '20px 24px' }}>
          <JobAlertsPanel lang={lang} />
        </div>
      )}

      {/* Mine Opslag — business management tab */}
      {tab === 'mine' ? (
        myJobs.length === 0 ? (
          <div className="p-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>{t.jobNoJobs}</div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {myJobs.map(job => (
              <div key={job.id} className="p-card" style={{ opacity: job.active ? 1 : 0.55 }}>
                <div style={{ display: 'flex', gap: 12, alignItems: 'flex-start' }}>
                  <div style={{ width: 40, height: 40, borderRadius: 8, background: job.company_color || '#1877F2', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: 800, fontSize: 18, flexShrink: 0 }}>
                    {(job.company_name || '?')[0]}
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
                      <span style={{ fontWeight: 700, fontSize: 15 }}>{job.title}</span>
                      <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 20, background: job.active ? '#F0FAF4' : '#f5f5f5', color: job.active ? '#2D6A4F' : '#888', fontWeight: 600 }}>
                        {job.active ? t.jobStatusActive : t.jobStatusClosed}
                      </span>
                    </div>
                    <div style={{ fontSize: 13, color: '#666', marginTop: 2 }}>
                      {job.company_name} · {job.location || '—'}{job.remote ? ` · ${t.jobRemote}` : ''} · {typeLabels[job.type] || job.type}
                    </div>
                    {(job.salary_min || job.salary_max) && (
                      <div style={{ fontSize: 13, color: '#2D6A4F', fontWeight: 600, marginTop: 4 }}>
                        💰 {job.salary_min ? job.salary_min.toLocaleString() : '?'} – {job.salary_max ? job.salary_max.toLocaleString() : '?'} {job.salary_currency || 'DKK'} / {job.salary_period === 'annual' ? (t.year) : (t.mo)}
                      </div>
                    )}
                    {job.share_count > 0 && (
                      <div style={{ fontSize: 12, color: '#666', marginTop: 4 }}>
                        🔗 {`${t.sharedTimesPrefix}${job.share_count}${job.share_count === 1 ? t.sharedTimesSuffix : t.sharedTimesSuffixPlural}`}
                      </div>
                    )}
                    <div style={{ display: 'flex', gap: 8, marginTop: 10, flexWrap: 'wrap' }}>
                      <button
                        onClick={() => setEditJob(job)}
                        style={{ padding: '6px 14px', borderRadius: 8, border: '1px solid #ddd', background: '#fff', fontSize: 13, cursor: 'pointer', fontWeight: 600 }}
                      >
                        ✏️ {t.jobEdit}
                      </button>
                      <button
                        onClick={() => handleToggleActive(job)}
                        style={{ padding: '6px 14px', borderRadius: 8, border: `1px solid ${job.active ? '#e74c3c' : '#2D6A4F'}`, background: job.active ? '#fff5f5' : '#F0FAF4', color: job.active ? '#e74c3c' : '#2D6A4F', fontSize: 13, cursor: 'pointer', fontWeight: 600 }}
                      >
                        {job.active ? `🚫 ${t.jobClose}` : `✅ ${t.jobReopen}`}
                      </button>
                      <button
                        onClick={() => openApplicants(job)}
                        style={{ padding: '6px 14px', borderRadius: 8, border: '1px solid #1877F2', background: '#EBF4FF', color: '#1877F2', fontSize: 13, cursor: 'pointer', fontWeight: 600 }}
                      >
                        👥 {t.applicants}
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )
      ) : loading ? (
        <div className="p-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>⏳</div>
      ) : displayJobs.length === 0 ? (
        <div className="p-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>{t.jobNoJobs}</div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {displayJobs.map(job => (
            <JobCard
              key={job.id}
              job={job}
              t={t}
              lang={lang}
              currentUser={currentUser}
              onSaveToggle={(id, saved) => {
                setJobs(prev => prev.map(j => j.id === id ? { ...j, saved } : j))
                setSavedJobs(prev => saved ? [...prev, job] : prev.filter(j => j.id !== id))
              }}
              onTrackChange={(id, status) => {
                setJobs(prev => prev.map(j => j.id === id ? { ...j, track_status: status } : j))
                setSavedJobs(prev => prev.map(j => j.id === id ? { ...j, track_status: status } : j))
                if (status) {
                  setTrackedJobs(prev => {
                    const exists = prev.find(j => j.id === id)
                    return exists ? prev.map(j => j.id === id ? { ...j, track_status: status } : j) : [...prev, { ...job, track_status: status }]
                  })
                } else {
                  setTrackedJobs(prev => prev.filter(j => j.id !== id))
                }
              }}
              onShare={(jobId) => setShareJobId(jobId)}
              onViewCompany={(companyId) => {
                onNavigate?.('companies', companyId)
              }}
              onContactCompany={(companyId) => {
                // Fetch company to show lead modal
                csrfFetch(`/api/companies/${companyId}`, { credentials: 'include' })
                  .then(r => r.ok ? r.json() : null)
                  .then(data => {
                    if (data) setContactCompanyLead(data)
                  })
                  .catch(() => {})
              }}
            />
          ))}
        </div>
      )}

      {showCreate && (
        <CreateJobModal
          t={t}
          lang={lang}
          companies={myCompanies}
          onClose={() => setShowCreate(false)}
          onCreate={(job) => { setJobs(prev => [job, ...prev]); setShowCreate(false); refreshMyJobs() }}
        />
      )}
      {editJob && (
        <CreateJobModal
          t={t}
          lang={lang}
          companies={myCompanies}
          editJob={editJob}
          onClose={() => setEditJob(null)}
          onCreate={() => { setEditJob(null); refreshMyJobs() }}
        />
      )}
      {applicantsJob && (
        <div className="modal-backdrop" onClick={() => setApplicantsJob(null)}>
          <div className="p-msg-modal" style={{ maxWidth: 560, maxHeight: '80vh', overflowY: 'auto' }} onClick={e => e.stopPropagation()}>
            <div className="p-msg-modal-header">
              <span>👥 {t.applicants} — {applicantsJob.title}</span>
              <button className="p-msg-modal-close" onClick={() => setApplicantsJob(null)}>✕</button>
            </div>
            {applicantsLoading ? (
              <div style={{ padding: 40, textAlign: 'center', color: '#888' }}>⏳</div>
            ) : applicants.length === 0 ? (
              <div style={{ padding: 32, textAlign: 'center', color: '#888' }}>
                {t.noApplicantsYet}
              </div>
            ) : (
              <div style={{ padding: '8px 0' }}>
                {applicants.map(app => (
                  <div key={app.id} style={{ padding: '12px 20px', borderBottom: '1px solid #f0f0f0' }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: 12 }}>
                      <div className="p-avatar-sm" style={{ background: nameToColor(app.name), flexShrink: 0 }}>{getInitials(app.name)}</div>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontWeight: 700, fontSize: 14 }}>{app.name}</div>
                        <div style={{ fontSize: 12, color: '#888' }}>{app.email}</div>
                        {app.message && <div style={{ fontSize: 13, color: '#555', marginTop: 6, lineHeight: 1.5 }}>{app.message}</div>}
                        <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap', marginTop: 4 }}>
                          {app.cv_url && (
                            <a href={app.cv_url} target="_blank" rel="noopener noreferrer" style={{ fontSize: 12, color: '#1877F2', display: 'inline-block' }}>
                              📄 {t.viewCV}
                            </a>
                          )}
                          {app.application_letter_url && (
                            <a href={app.application_letter_url} target="_blank" rel="noopener noreferrer" style={{ fontSize: 12, color: '#7C3AED', display: 'inline-block' }}>
                              ✍️ {t.viewCoverLetter}
                            </a>
                          )}
                        </div>
                        <div style={{ fontSize: 11, color: '#aaa', marginTop: 4 }}>
                          {new Date(app.created_at).toLocaleDateString(getLocale(lang), { day: 'numeric', month: 'short', year: 'numeric' })}
                        </div>
                      </div>
                      <select
                        value={app.status}
                        onChange={e => {
                          const newStatus = e.target.value
                          apiUpdateJobApplication(applicantsJob.id, app.id, newStatus).then(() => {
                            setApplicants(prev => prev.map(a => a.id === app.id ? { ...a, status: newStatus } : a))
                          }).catch(() => {})
                        }}
                        style={{ fontSize: 12, padding: '4px 8px', borderRadius: 8, border: `1px solid ${app.status === 'shortlisted' ? '#2D6A4F' : app.status === 'rejected' ? '#e74c3c' : app.status === 'reviewed' ? '#1877F2' : '#ddd'}`, background: '#fff', color: '#333', cursor: 'pointer' }}
                      >
                        <option value="pending">{t.pending}</option>
                        <option value="reviewed">{t.reviewed}</option>
                        <option value="shortlisted">{t.shortlisted}</option>
                        <option value="rejected">{t.jobTrackRejected}</option>
                      </select>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
      {shareJobId && (
        <div className="modal-backdrop" onClick={() => { setShareJobId(null); setShareQuery(''); setShareUsers([]) }}>
          <div className="p-msg-modal" style={{ maxWidth: 480 }} onClick={e => e.stopPropagation()}>
            <div className="p-msg-modal-header">
              <span>🔗 {t.shareJob}</span>
              <button className="p-msg-modal-close" onClick={() => { setShareJobId(null); setShareQuery(''); setShareUsers([]) }}>✕</button>
            </div>
            <div style={{ padding: '20px' }}>
              {/* Already shared with */}
              {sharedWithUsers.length > 0 && (
                <div style={{ marginBottom: 16, paddingBottom: 16, borderBottom: '1px solid #eee' }}>
                  <div style={{ fontSize: 12, fontWeight: 600, color: '#666', marginBottom: 10 }}>
                    {t.sharedWith} ({sharedWithUsers.length})
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                    {sharedWithUsers.map(user => (
                      <div key={user.id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '8px 10px', borderRadius: 8, background: '#F0FAF4' }}>
                        <div className="p-avatar-sm" style={{ background: nameToColor(user.name), flexShrink: 0 }}>{getInitials(user.name)}</div>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ fontWeight: 600, fontSize: 14 }}>{user.name}</div>
                          <div style={{ fontSize: 12, color: '#888' }}>@{user.handle || user.username}</div>
                        </div>
                        <span style={{ padding: '4px 10px', borderRadius: 4, background: '#2D6A4F', color: '#fff', fontSize: 11, fontWeight: 600, flexShrink: 0 }}>
                          {t.shared}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Search for more users */}
              <div style={{ fontSize: 12, fontWeight: 600, color: '#666', marginBottom: 10 }}>
                {t.shareWithAnotherUser}
              </div>
              <input
                type="text"
                placeholder={t.searchForUser}
                value={shareQuery}
                onChange={e => {
                  setShareQuery(e.target.value)
                  if (e.target.value.length > 0) {
                    csrfFetch(`/api/users/search?q=${encodeURIComponent(e.target.value)}`, { credentials: 'include' })
                      .then(r => r.ok ? r.json() : null)
                      .then(data => setShareUsers(Array.isArray(data) ? data : data?.users || []))
                      .catch(() => {})
                  } else {
                    setShareUsers([])
                  }
                }}
                style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #ddd', fontSize: 14, marginBottom: 12 }}
              />
              {shareUsers.length === 0 && shareQuery.length > 0 && (
                <div style={{ padding: 20, textAlign: 'center', color: '#888', fontSize: 13 }}>
                  {t.adminModNoUsers}
                </div>
              )}
              <div style={{ maxHeight: 250, overflowY: 'auto' }}>
                {shareUsers.map(user => {
                  const isAlreadyShared = sharedWithUsers.some(u => u.id === user.id)
                  return (
                    <div key={user.id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px', borderRadius: 8, background: isAlreadyShared ? '#f5f5f5' : '#f9f9f9', marginBottom: 8, opacity: isAlreadyShared ? 0.6 : 1 }}>
                      <div className="p-avatar-sm" style={{ background: nameToColor(user.name), flexShrink: 0 }}>{getInitials(user.name)}</div>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontWeight: 600, fontSize: 14 }}>{user.name}</div>
                        <div style={{ fontSize: 12, color: '#888' }}>@{user.handle || user.username}</div>
                      </div>
                      <button
                        disabled={sharingSending || isAlreadyShared}
                        onClick={() => {
                          setShareSending(true)
                          apiShareJob(shareJobId, user.id).then(data => {
                            if (data) {
                              setSharedWithUsers(prev => [...prev, user])
                              setShareQuery('')
                              setShareUsers([])
                            }
                            setShareSending(false)
                          }).catch(() => setShareSending(false))
                        }}
                        style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: isAlreadyShared ? '#ccc' : '#2D6A4F', color: '#fff', fontSize: 12, fontWeight: 600, cursor: isAlreadyShared ? 'default' : 'pointer', flexShrink: 0, opacity: sharingSending ? 0.7 : 1 }}
                      >
                        {isAlreadyShared ? (t.shared2) : (sharingSending ? '⏳' : t.eventShareConfirm)}
                      </button>
                    </div>
                  )
                })}
              </div>
            </div>
          </div>
        </div>
      )}

      {contactCompanyLead && (
        <CompanyLeadModal company={contactCompanyLead} t={t} lang={lang} onClose={() => setContactCompanyLead(null)} />
      )}
    </div>
  )
}

