function CreateJobModal({ t, lang, companies, onClose, onCreate, editJob }) {
  const isEdit = !!editJob
  const [title, setTitle] = useState(editJob?.title || '')
  const [companyId, setCompanyId] = useState(editJob?.company_id || companies[0]?.id || '')
  const [location, setLocation] = useState(editJob?.location || '')
  const [remote, setRemote] = useState(!!editJob?.remote)
  const [type, setType] = useState(editJob?.type || 'fulltime')
  const [description, setDescription] = useState(editJob?.description || '')
  const [requirements, setRequirements] = useState(editJob?.requirements || '')
  const [applyLink, setApplyLink] = useState(editJob?.apply_link || '')
  const [contactEmail, setContactEmail] = useState(editJob?.contact_email || '')
  const [deadline, setDeadline] = useState(editJob?.deadline ? editJob.deadline.split('T')[0] : '')
  const [salaryMin, setSalaryMin] = useState(editJob?.salary_min || '')
  const [salaryMax, setSalaryMax] = useState(editJob?.salary_max || '')
  const [salaryCurrency, setSalaryCurrency] = useState(editJob?.salary_currency || 'DKK')
  const [salaryPeriod, setSalaryPeriod] = useState(editJob?.salary_period || 'monthly')
  const [collectiveAgreement, setCollectiveAgreement] = useState(editJob?.collective_agreement || '')

  useEffect(() => {
    const h = (e) => { if (e.key === 'Escape') onClose() }
    document.addEventListener('keydown', h)
    return () => document.removeEventListener('keydown', h)
  }, [onClose])

  const fS = { display: 'block', width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #ddd', fontSize: 14, boxSizing: 'border-box', fontFamily: 'inherit' }
  const lS = { display: 'block', fontSize: 13, fontWeight: 600, color: '#555', marginBottom: 4, marginTop: 14 }

  const handleSubmit = async (e) => {
    e.preventDefault()
    if (!title.trim()) return
    const payload = {
      company_id: Number(companyId) || companies[0]?.id,
      title: title.trim(),
      location: location.trim() || null,
      remote,
      type,
      description: description.trim() || null,
      requirements: requirements.trim() || null,
      apply_link: applyLink.trim() || null,
      contact_email: contactEmail.trim() || null,
      deadline: deadline || null,
      salary_min: salaryMin ? Number(salaryMin) : null,
      salary_max: salaryMax ? Number(salaryMax) : null,
      salary_currency: salaryCurrency,
      salary_period: salaryPeriod,
      collective_agreement: (collectiveAgreement && collectiveAgreement !== '__anden__') ? collectiveAgreement.trim() : null,
    }
    try {
      const url = isEdit ? `/api/jobs/${editJob.id}` : '/api/jobs'
      const res = await csrfFetch(url, {
        method: isEdit ? 'PUT' : 'POST', credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      })
      if (!res.ok) { const err = await res.json(); alert(err.error || 'Fejl'); return }
      const job = await res.json()
      onCreate(job)
    } catch { alert(t.networkError) }
  }

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="p-event-create-modal" onClick={e => e.stopPropagation()} style={{ maxHeight: '90vh', overflowY: 'auto' }}>
        <h3 style={{ margin: '0 0 4px', fontSize: 18, fontWeight: 700 }}>
          💼 {isEdit ? (t.editJobListing) : t.createJob}
        </h3>
        <form onSubmit={handleSubmit}>
          {!isEdit && companies.length > 0 && (
            <>
              <label style={lS}>{t.companies}</label>
              <select style={fS} value={companyId} onChange={e => setCompanyId(e.target.value)}>
                {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </>
          )}
          <label style={lS}>{t.jobTitle} <span className="req">*</span></label>
          <input style={fS} value={title} onChange={e => setTitle(e.target.value)} required placeholder={t.eGSeniorDesigner} />
          <label style={lS}>{t.jobLocation} <span className="req">*</span></label>
          <LocationAutocomplete
            value={location}
            onChange={setLocation}
            onSelect={loc => loc && setLocation(loc.name)}
            lang={lang}
            placeholder={t.cityCountryOrRemote}
            required
            inputStyle={fS}
          />
          <label style={{ ...lS, display: 'flex', alignItems: 'center', gap: 8 }}>
            <input type="checkbox" checked={remote} onChange={e => setRemote(e.target.checked)} />
            {t.jobRemote}
          </label>
          <label style={lS}>{t.jobType}</label>
          <select style={fS} value={type} onChange={e => setType(e.target.value)}>
            <option value="fulltime">{t.jobTypeFullTime}</option>
            <option value="parttime">{t.jobTypePartTime}</option>
            <option value="freelance">{t.jobTypeFreelance}</option>
            <option value="internship">{t.jobTypeInternship}</option>
          </select>
          <label style={lS}>{t.jobDescription}</label>
          <textarea style={{ ...fS, minHeight: 80, resize: 'vertical' }} value={description} onChange={e => setDescription(e.target.value)} placeholder={t.describeThePosition} />
          <label style={lS}>{t.jobRequirements}</label>
          <textarea style={{ ...fS, minHeight: 60, resize: 'vertical' }} value={requirements} onChange={e => setRequirements(e.target.value)} placeholder={t.requirementsForApplicants} />

          {/* EU Pay Transparency — Salary fields */}
          <div style={{ marginTop: 18, padding: '12px 14px', borderRadius: 8, background: '#F0FAF4', border: '1px solid #b7dfc8' }}>
            <div style={{ fontSize: 13, fontWeight: 700, color: '#2D6A4F', marginBottom: 6 }}>
              💶 {t.jobSalaryRange}
            </div>
            <div style={{ fontSize: 12, color: '#4a7c62', marginBottom: 10, lineHeight: 1.5 }}>
              ℹ️ {t.jobSalaryNote}
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 10 }}>
              <div>
                <label style={{ ...lS, marginTop: 0 }}>{t.jobSalaryMin}</label>
                <input style={fS} type="number" min="0" value={salaryMin} onChange={e => setSalaryMin(e.target.value)} placeholder="50000" />
              </div>
              <div>
                <label style={{ ...lS, marginTop: 0 }}>{t.jobSalaryMax}</label>
                <input style={fS} type="number" min="0" value={salaryMax} onChange={e => setSalaryMax(e.target.value)} placeholder="70000" />
              </div>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
              <div>
                <label style={{ ...lS, marginTop: 0 }}>{t.jobSalaryCurrency}</label>
                <select style={fS} value={salaryCurrency} onChange={e => setSalaryCurrency(e.target.value)}>
                  <option value="DKK">DKK</option>
                  <option value="EUR">EUR</option>
                  <option value="SEK">SEK</option>
                  <option value="NOK">NOK</option>
                  <option value="GBP">GBP</option>
                  <option value="USD">USD</option>
                </select>
              </div>
              <div>
                <label style={{ ...lS, marginTop: 0 }}>{t.jobSalaryPeriod}</label>
                <select style={fS} value={salaryPeriod} onChange={e => setSalaryPeriod(e.target.value)}>
                  <option value="monthly">{t.jobSalaryMonthly}</option>
                  <option value="annual">{t.jobSalaryAnnual}</option>
                </select>
              </div>
            </div>
            <div>
              <label style={{ ...lS, marginTop: 10 }}>{t.jobCollectiveAgreement}</label>
              <select
                style={fS}
                value={DK_OVERENSKOMSTER.flatMap(g => g.options).includes(collectiveAgreement) ? collectiveAgreement : (collectiveAgreement === '' ? '' : '__anden__')}
                onChange={e => {
                  if (e.target.value === '__anden__') setCollectiveAgreement('__anden__')
                  else setCollectiveAgreement(e.target.value)
                }}
              >
                <option value="">{t.selectAgreement}</option>
                <option value="Ingen overenskomst">{t.noCollectiveAgreement}</option>
                {DK_OVERENSKOMSTER.map(group => (
                  <optgroup key={group.group} label={group.group}>
                    {group.options.map(o => <option key={o} value={o}>{o}</option>)}
                  </optgroup>
                ))}
                <option value="__anden__">{t.otherTypeManually}</option>
              </select>
              {(collectiveAgreement === '__anden__' || (!DK_OVERENSKOMSTER.flatMap(g => g.options).includes(collectiveAgreement) && collectiveAgreement !== '' && collectiveAgreement !== 'Ingen overenskomst')) && (
                <input
                  style={{ ...fS, marginTop: 6 }}
                  value={collectiveAgreement === '__anden__' ? '' : collectiveAgreement}
                  onChange={e => setCollectiveAgreement(e.target.value)}
                  placeholder={t.typeAgreementName}
                  autoFocus
                />
              )}
            </div>
          </div>

          <label style={lS}>{t.jobApplyLink}</label>
          <input style={fS} value={applyLink} onChange={e => setApplyLink(e.target.value)} placeholder="https://..." />
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
            <div>
              <label style={lS}>{t.jobContactEmail}</label>
              <input style={fS} type="email" value={contactEmail} onChange={e => setContactEmail(e.target.value)} autoComplete="email" placeholder="job@firma.dk" />
            </div>
            <div>
              <label style={lS}>{t.jobDeadline}</label>
              <input style={fS} type="date" lang={getLocale(lang)} value={deadline} onChange={e => setDeadline(e.target.value)} />
            </div>
          </div>
          <div style={{ display: 'flex', gap: 10, marginTop: 24 }}>
            <button type="button" onClick={onClose} style={{ flex: 1, padding: 10, borderRadius: 8, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 14 }}>{t.eventCancel}</button>
            <button type="submit" style={{ flex: 2, padding: 10, borderRadius: 8, border: 'none', background: '#2D6A4F', color: '#fff', cursor: 'pointer', fontSize: 14, fontWeight: 700 }}>
              {isEdit ? (t.eventSave) : t.jobPost}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

// ── OpenStreetMap (CDN Leaflet — no npm dependency) ──
const _osmGeoCache = new Map()
async function _osmGeocode(location) {
  if (!location) return null
  if (_osmGeoCache.has(location)) return _osmGeoCache.get(location)
  try {
    const res = await csrfFetch(
      `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(location)}&format=json&limit=1`,
      { headers: { 'Accept-Language': 'da,en' } }
    )
    const data = await res.json()
    const result = data[0] ? { lat: parseFloat(data[0].lat), lon: parseFloat(data[0].lon) } : null
    _osmGeoCache.set(location, result)
    return result
  } catch { return null }
}

let _leafletPromise = null
function _loadLeaflet() {
  if (_leafletPromise) return _leafletPromise
  _leafletPromise = new Promise((resolve) => {
    if (window.L) { resolve(window.L); return }
    const link = document.createElement('link')
    link.rel = 'stylesheet'
    link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css'
    document.head.appendChild(link)
    const script = document.createElement('script')
    script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js'
    script.onload = () => resolve(window.L)
    document.head.appendChild(script)
  })
  return _leafletPromise
}

function OsmMap({ location, height = 220, lang }) {
  const t = getTranslations(lang)
  const containerRef = useRef(null)
  const instanceRef = useRef(null)
  const [status, setStatus] = useState('loading')
  useEffect(() => {
    if (!location) { setStatus('none'); return }
    let cancelled = false
    setStatus('loading')
    Promise.all([_loadLeaflet(), _osmGeocode(location)]).then(([L, coords]) => {
      if (cancelled || !containerRef.current) return
      if (!coords) { setStatus('notfound'); return }
      if (instanceRef.current) { instanceRef.current.remove(); instanceRef.current = null }
      const map = L.map(containerRef.current, { scrollWheelZoom: false }).setView([coords.lat, coords.lon], 13)
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
      }).addTo(map)
      L.marker([coords.lat, coords.lon]).addTo(map).bindPopup(location)
      instanceRef.current = map
      setStatus('ok')
    })
    return () => {
      cancelled = true
      if (instanceRef.current) { instanceRef.current.remove(); instanceRef.current = null }
    }
  }, [location])
  if (!location || status === 'none' || status === 'notfound') return null
  return (
    <div style={{ position: 'relative', height, borderRadius: 10, overflow: 'hidden' }}>
      {status === 'loading' && (
        <div style={{ position: 'absolute', inset: 0, background: '#f0ede8', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#aaa', fontSize: 13, gap: 6, zIndex: 1 }}>
          🗺️ {t.loadingMap}
        </div>
      )}
      <div ref={containerRef} style={{ height, width: '100%' }} />
    </div>
  )
}

// ── Marketplace ──
const MARKETPLACE_CATEGORIES = [
  { key: 'electronics', icon: '🖥️', labelKey: 'marketplaceCatElectronics' },
  { key: 'furniture',   icon: '🪑', labelKey: 'marketplaceCatFurniture' },
  { key: 'clothing',    icon: '👕', labelKey: 'marketplaceCatClothing' },
  { key: 'sports',      icon: '⚽', labelKey: 'marketplaceCatSports' },
  { key: 'books',       icon: '📚', labelKey: 'marketplaceCatBooks' },
  { key: 'garden',      icon: '🌱', labelKey: 'marketplaceCatGarden' },
  { key: 'vehicles',    icon: '🚗', labelKey: 'marketplaceCatVehicles' },
  { key: 'other',       icon: '📦', labelKey: 'marketplaceCatOther' },
]

function MarketplaceMapView({ listings, lang, onSelect }) {
  const t = getTranslations(lang)
  const containerRef = useRef(null)
  const instanceRef = useRef(null)
  const listingTitle = (l) => typeof l.title === 'string' ? l.title : (l.title?.[lang] || l.title?.da || '')
  useEffect(() => {
    const withLocation = listings.filter(l => l.location && !l.sold)
    if (!withLocation.length || !containerRef.current) return
    let cancelled = false
    Promise.all([
      _loadLeaflet(),
      Promise.all(withLocation.map(l => _osmGeocode(l.location).then(c => c ? { listing: l, lat: c.lat, lon: c.lon } : null)))
    ]).then(([L, results]) => {
      if (cancelled || !containerRef.current) return
      const markers = results.filter(Boolean)
      if (instanceRef.current) { instanceRef.current.remove(); instanceRef.current = null }
      const map = L.map(containerRef.current, { scrollWheelZoom: true }).setView([55.676, 12.568], 9)
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
      }).addTo(map)
      markers.forEach(({ listing, lat, lon }) => {
        const popup = `<strong>${listingTitle(listing)}</strong><br>📍 ${listing.location}<br>${listing.price ? listing.price.toLocaleString() + ' kr.' : (t.marketplacePriceNegotiable)}`
        L.marker([lat, lon]).addTo(map).bindPopup(popup).on('click', () => onSelect(listing))
      })
      if (markers.length) {
        const group = L.featureGroup(markers.map(({ lat, lon }) => L.marker([lat, lon])))
        map.fitBounds(group.getBounds().pad(0.2))
      }
      instanceRef.current = map
    })
    return () => {
      cancelled = true
      if (instanceRef.current) { instanceRef.current.remove(); instanceRef.current = null }
    }
  }, [listings]) // eslint-disable-line react-hooks/exhaustive-deps
  return (
    <div style={{ borderRadius: 12, overflow: 'hidden', marginBottom: 16 }}>
      <div ref={containerRef} style={{ height: 480, width: '100%' }} />
    </div>
  )
}

function MarketplaceStatsPanel({ stats, loading, myListings, t, lang }) {
  const MARKETPLACE_CATEGORIES_LOCAL = [
    { key: 'electronics', icon: '💻' }, { key: 'clothing', icon: '👗' }, { key: 'furniture', icon: '🪑' },
    { key: 'books', icon: '📚' }, { key: 'sports', icon: '⚽' }, { key: 'toys', icon: '🧸' },
    { key: 'home', icon: '🏠' }, { key: 'art', icon: '🎨' }, { key: 'garden', icon: '🌿' },
    { key: 'vehicles', icon: '🚗' }, { key: 'other', icon: '📦' },
  ]
  const catIcon = (key) => MARKETPLACE_CATEGORIES_LOCAL.find(c => c.key === key)?.icon || '📦'

  const s = {
    grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(130px, 1fr))', gap: 12, marginBottom: 20 },
    card: { background: '#fff', borderRadius: 12, padding: '16px 18px', boxShadow: '0 1px 4px rgba(0,0,0,.08)', textAlign: 'center' },
    val: { fontSize: 28, fontWeight: 800, color: '#2D6A4F', lineHeight: 1.1 },
    lbl: { fontSize: 12, color: '#888', marginTop: 4, fontWeight: 500 },
    section: { marginBottom: 20 },
    sectionTitle: { fontSize: 13, fontWeight: 700, color: '#555', marginBottom: 10, textTransform: 'uppercase', letterSpacing: '0.05em' },
    row: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '8px 0', borderBottom: '1px solid #f0f0f0' },
    barWrap: { background: '#f0f0f0', borderRadius: 4, height: 8, flex: 1, margin: '0 10px', overflow: 'hidden' },
    bar: (pct, color) => ({ width: `${pct}%`, height: '100%', background: color || '#2D6A4F', borderRadius: 4, transition: 'width 0.4s' }),
  }

  if (loading) return <div style={{ textAlign: 'center', padding: 40, color: '#888' }}>{t.loading2}</div>

  // Use local myListings count if server stats not yet available
  const totalFromLocal = myListings.length
  const activeFromLocal = myListings.filter(l => !l.sold).length
  const soldFromLocal = myListings.filter(l => l.sold).length

  const overview = stats?.overview || { total: totalFromLocal, active: activeFromLocal, sold: soldFromLocal, boosted: 0 }
  const views = stats?.views || { total: 0, last7Days: 0, today: 0 }
  const topListings = stats?.topListings || []
  const categories = stats?.categories || []
  const viewTrend = stats?.viewTrend || []

  // Build last 14 days date labels for trend bar chart
  const today = new Date()
  const trendDays = Array.from({ length: 14 }, (_, i) => {
    const d = new Date(today)
    d.setDate(d.getDate() - 13 + i)
    return d.toISOString().slice(0, 10)
  })
  const trendMap = Object.fromEntries(viewTrend.map(r => [r.date?.slice(0, 10), r.views]))
  const trendValues = trendDays.map(d => trendMap[d] || 0)
  const trendMax = Math.max(...trendValues, 1)

  const maxCatCount = Math.max(...categories.map(c => c.count), 1)
  const maxViews = Math.max(...topListings.map(l => l.views), 1)

  const hasAnyData = overview.total > 0

  if (!hasAnyData) {
    return (
      <div className="p-card" style={{ textAlign: 'center', padding: '40px 24px', color: '#888' }}>
        <div style={{ fontSize: 40, marginBottom: 12 }}>📊</div>
        <div style={{ fontWeight: 600, fontSize: 15, color: '#555', marginBottom: 8 }}>
          {t.noStatisticsYet}
        </div>
        <div style={{ fontSize: 14, lineHeight: 1.6 }}>{t.marketplaceStatsNoData}</div>
      </div>
    )
  }

  return (
    <div>
      {/* Overview numbers */}
      <div style={s.section}>
        <div style={s.sectionTitle}>{t.marketplaceStatsOverview}</div>
        <div style={s.grid}>
          <div style={s.card}><div style={s.val}>{overview.active}</div><div style={s.lbl}>{t.marketplaceStatsActive}</div></div>
          <div style={s.card}><div style={{ ...s.val, color: '#888' }}>{overview.sold}</div><div style={s.lbl}>{t.marketplaceStatsSold}</div></div>
          <div style={{ ...s.card }}><div style={{ ...s.val, color: '#F4A261' }}>{overview.boosted}</div><div style={s.lbl}>{t.marketplaceStatsBoosted}</div></div>
          <div style={s.card}><div style={s.val}>{views.total}</div><div style={s.lbl}>{t.marketplaceStatsTotalViews}</div></div>
          <div style={s.card}><div style={{ ...s.val, color: '#3498db' }}>{views.last7Days}</div><div style={s.lbl}>{t.marketplaceStatsViews7Days}</div></div>
          <div style={s.card}><div style={{ ...s.val, color: '#9b59b6' }}>{views.today}</div><div style={s.lbl}>{t.marketplaceStatsViewsToday}</div></div>
        </div>
      </div>

      {/* Views trend (last 14 days) */}
      {viewTrend.length > 0 && (
        <div style={s.section}>
          <div style={s.sectionTitle}>{t.marketplaceStatsViewTrend}</div>
          <div className="p-card" style={{ padding: '12px 16px' }}>
            <div style={{ display: 'flex', alignItems: 'flex-end', gap: 3, height: 64 }}>
              {trendValues.map((v, i) => (
                <div key={i} title={`${trendDays[i]}: ${v}`} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'flex-end', height: '100%' }}>
                  <div style={{ width: '100%', background: v > 0 ? '#2D6A4F' : '#e8e8e8', borderRadius: '3px 3px 0 0', height: `${Math.max((v / trendMax) * 100, v > 0 ? 8 : 2)}%`, transition: 'height 0.3s' }} />
                </div>
              ))}
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10, color: '#bbb', marginTop: 4 }}>
              <span>{trendDays[0]?.slice(5)}</span>
              <span>{trendDays[6]?.slice(5)}</span>
              <span>{trendDays[13]?.slice(5)}</span>
            </div>
          </div>
        </div>
      )}

      {/* Top listings */}
      {topListings.length > 0 && (
        <div style={s.section}>
          <div style={s.sectionTitle}>{t.marketplaceStatsTopListings}</div>
          <div className="p-card" style={{ padding: '8px 16px' }}>
            {topListings.map(l => (
              <div key={l.id} style={s.row}>
                <span style={{ fontSize: 13, color: l.sold ? '#aaa' : '#333', maxWidth: 160, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {catIcon(l.category)} {l.title}{l.sold ? ` (${t.marketplaceSold || 'solgt'})` : ''}
                </span>
                <div style={s.barWrap}>
                  <div style={s.bar((l.views / maxViews) * 100)} />
                </div>
                <span style={{ fontSize: 12, color: '#666', minWidth: 50, textAlign: 'right' }}>{l.views} {t.marketplaceStatsViews}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Category distribution */}
      {categories.length > 0 && (
        <div style={s.section}>
          <div style={s.sectionTitle}>{t.marketplaceStatsCategories}</div>
          <div className="p-card" style={{ padding: '8px 16px' }}>
            {categories.map(c => (
              <div key={c.category} style={s.row}>
                <span style={{ fontSize: 13, color: '#333', minWidth: 100 }}>{catIcon(c.category)} {c.category}</span>
                <div style={s.barWrap}>
                  <div style={s.bar((c.count / maxCatCount) * 100, '#3498db')} />
                </div>
                <span style={{ fontSize: 12, color: '#666', minWidth: 30, textAlign: 'right' }}>{c.count}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

function MarketplacePage({ lang, t, currentUser, maxPhotos = 4, onContactSeller, onViewProfile, onMakeOffer }) {
  const [searchParams, setSearchParams] = useSearchParams()
  const tab = searchParams.get('tab') || 'browse'
  const filters = { category: searchParams.get('category') || '', location: searchParams.get('location') || '', q: searchParams.get('q') || '' }
  const setTab = (t) => setSearchParams(p => { const n = new URLSearchParams(p); t === 'browse' ? n.delete('tab') : n.set('tab', t); return n })
  const setFilters = (updater) => {
    const next = typeof updater === 'function' ? updater(filters) : updater
    setSearchParams(p => {
      const n = new URLSearchParams(p)
      next.category ? n.set('category', next.category) : n.delete('category')
      next.location ? n.set('location', next.location) : n.delete('location')
      next.q ? n.set('q', next.q) : n.delete('q')
      return n
    })
  }
  const [listings, setListings] = useState([])
  const [myListings, setMyListings] = useState([])
  const [selectedListing, setSelectedListing] = useState(null)
  const [showForm, setShowForm] = useState(false)
  const [editListing, setEditListing] = useState(null)
  const [deleteConfirmId, setDeleteConfirmId] = useState(null)
  const [boostedIds, setBoostedIds] = useState({})
  const [boostMsg, setBoostMsg] = useState(null)
  const [formError, setFormError] = useState(null)
  const [marketplaceStats, setMarketplaceStats] = useState(null)
  const [statsLoading, setStatsLoading] = useState(false)
  const [kwAlerts, setKwAlerts] = useState([])
  const [kwInput, setKwInput] = useState('')
  const [kwOpen, setKwOpen] = useState(false)
  const [kwEditId, setKwEditId] = useState(null)
  const [kwEditVal, setKwEditVal] = useState('')

  const isBoosted = (listing) => boostedIds[listing.id] || (listing.boosted_until && new Date(listing.boosted_until) > new Date())
  const catIcon = (key) => MARKETPLACE_CATEGORIES.find(c => c.key === key)?.icon || '📦'
  const catLabel = (key) => { const f = MARKETPLACE_CATEGORIES.find(c => c.key === key); return f ? `${f.icon} ${t[f.labelKey] || key}` : key }
  const listingTitle = (l) => typeof l.title === 'string' ? l.title : (l.title?.[lang] || l.title?.da || '')
  const listingDesc  = (l) => typeof l.description === 'string' ? l.description : (l.description?.[lang] || l.description?.da || '')

  useEffect(() => {
    apiFetchListings(filters).then(data => {
      const apiListings = data?.listings || (Array.isArray(data) ? data : null)
      if (apiListings) setListings(apiListings)
    })
  }, []) // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    apiGetMarketplaceAlerts().then(data => { if (data?.alerts) setKwAlerts(data.alerts) })
  }, [])

  useEffect(() => {
    if (tab === 'mine' || tab === 'stats') {
      apiFetchMyListings().then(data => { if (data?.listings || Array.isArray(data)) setMyListings(data?.listings || data) })
      setStatsLoading(true)
      apiGetMarketplaceStats().then(data => { if (data) setMarketplaceStats(data) }).finally(() => setStatsLoading(false))
    }
  }, [tab])

  const filtered = listings.filter(l => {
    if (l.sold) return false  // hide sold listings in Browse
    if (filters.category && l.category !== filters.category) return false
    if (filters.location && !l.location?.toLowerCase().includes(filters.location.toLowerCase())) return false
    if (filters.q) {
      const q = filters.q.toLowerCase()
      if (!listingTitle(l).toLowerCase().includes(q) && !listingDesc(l).toLowerCase().includes(q)) return false
    }
    return true
  })

  const handleCreate = async (formData, localListing) => {
    try {
      const result = await apiCreateListing(formData)
      const newL = result?.id ? result : { ...localListing, id: Date.now(), seller: currentUser.name, sellerId: currentUser.id, postedAt: new Date().toISOString().slice(0, 10), sold: false }
      setListings(prev => [newL, ...prev])
      setMyListings(prev => [newL, ...prev])
      setShowForm(false)
    } catch (err) {
      setFormError(err.message || 'Der skete en fejl – prøv igen')
    }
  }

  const handleUpdate = async (id, formData, localListing) => {
    try {
      setFormError(null)
      const result = await apiUpdateListing(id, formData)
      const updated = result || localListing
      setListings(prev => prev.map(l => l.id === id ? { ...l, ...updated } : l))
      setMyListings(prev => prev.map(l => l.id === id ? { ...l, ...updated } : l))
      setShowForm(false)
      setEditListing(null)
    } catch (err) {
      console.error('handleUpdate error:', err)
      setFormError(err.message || 'Der skete en fejl – prøv igen')
    }
  }

  const handleMarkSold = async (id) => {
    await apiMarkListingSold(id)
    setListings(prev => prev.map(l => l.id === id ? { ...l, sold: true } : l))
    setMyListings(prev => prev.map(l => l.id === id ? { ...l, sold: true } : l))
  }

  const handleRelist = async (id) => {
    await apiRelistListing(id)
    const today = new Date().toISOString().slice(0, 10)
    setListings(prev => prev.map(l => l.id === id ? { ...l, sold: false, postedAt: today } : l))
    setMyListings(prev => prev.map(l => l.id === id ? { ...l, sold: false, postedAt: today } : l))
  }

  const handleDelete = async (id) => {
    await apiDeleteListing(id)
    setListings(prev => prev.filter(l => l.id !== id))
    setMyListings(prev => prev.filter(l => l.id !== id))
    setDeleteConfirmId(null)
  }

  const handleBoost = async (id) => {
    const res = await apiBoostListing(id).catch(() => null)
    if (res?.checkoutUrl) {
      window.location.href = res.checkoutUrl
    } else {
      // Mollie not yet configured — show info message
      setBoostedIds(prev => ({ ...prev, [id]: true }))
      setBoostMsg(t.marketplaceBoostSuccess)
      setTimeout(() => setBoostMsg(null), 4000)
    }
  }

  const displayListings = tab === 'mine' ? myListings : filtered

  return (
    <div className="p-marketplace">
      {boostMsg && (
        <div style={{ background: '#40916C', color: '#fff', padding: '10px 16px', borderRadius: 8, marginBottom: 12, fontSize: 14, fontWeight: 600 }}>
          {boostMsg}
        </div>
      )}
      <div className="p-marketplace-header">
        <h2 className="p-section-title" style={{ margin: 0 }}>{t.marketplaceTitle}</h2>
        <button className="p-marketplace-create-btn" onClick={() => { setEditListing(null); setFormError(null); setShowForm(true) }}>
          {t.marketplaceCreateBtn}
        </button>
      </div>

      <div className="p-filter-tabs" style={{ marginBottom: 16 }}>
        <button className={`p-filter-tab${tab === 'browse' ? ' active' : ''}`} onClick={() => setTab('browse')}>
          🔍 {t.marketplaceBrowse}
        </button>
        <button className={`p-filter-tab${tab === 'map' ? ' active' : ''}`} onClick={() => setTab('map')}>
          🗺️ {t.mapView}
        </button>
        <button className={`p-filter-tab${tab === 'mine' ? ' active' : ''}`} onClick={() => setTab('mine')}>
          📋 {t.marketplaceMyListings}
        </button>
        <button className={`p-filter-tab${tab === 'stats' ? ' active' : ''}`} onClick={() => setTab('stats')}>
          📊 {t.marketplaceStats || (t.adminLivestreamStatsTab)}
        </button>
        <button className={`p-filter-tab${tab === 'wishlist' ? ' active' : ''}`} onClick={() => setTab('wishlist')}>
          ❤️ {t.wishlist}
        </button>
      </div>

      {tab === 'browse' && (
        <div className="p-marketplace-filters">
          <div style={{ position: 'relative' }}>
            <input
              className="p-search-input p-marketplace-search"
              style={{ width: '100%', boxSizing: 'border-box', paddingRight: filters.q ? 32 : undefined }}
              placeholder={t.marketplaceSearchPlaceholder}
              value={filters.q}
              onChange={e => setFilters(f => ({ ...f, q: e.target.value }))}
            />
            {filters.q && (
              <button onClick={() => setFilters(f => ({ ...f, q: '' }))} style={{ position: 'absolute', right: 10, top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: '#aaa', fontSize: 14, lineHeight: 1, padding: 2 }}>✕</button>
            )}
          </div>
          <div className="p-marketplace-filter-row">
            <select
              className="p-marketplace-select"
              value={filters.category}
              onChange={e => setFilters(f => ({ ...f, category: e.target.value }))}
            >
              <option value="">{t.marketplaceFilterAll}</option>
              {MARKETPLACE_CATEGORIES.map(c => (
                <option key={c.key} value={c.key}>{c.icon} {t[c.labelKey]}</option>
              ))}
            </select>
            <div style={{ position: 'relative', flex: 1 }}>
              <input
                className="p-marketplace-location-input"
                style={{ width: '100%', boxSizing: 'border-box', paddingRight: filters.location ? 32 : 12 }}
                placeholder={t.cityOrArea}
                value={filters.location}
                onChange={e => setFilters(f => ({ ...f, location: e.target.value }))}
              />
              {filters.location && (
                <button onClick={() => setFilters(f => ({ ...f, location: '' }))} style={{ position: 'absolute', right: 10, top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: '#aaa', fontSize: 14, lineHeight: 1, padding: 2 }}>✕</button>
              )}
            </div>
          </div>
        </div>
      )}

      {tab === 'map' && (
        <MarketplaceMapView listings={filtered} lang={lang} onSelect={setSelectedListing} />
      )}

      {tab === 'stats' && (
        <MarketplaceStatsPanel stats={marketplaceStats} loading={statsLoading} myListings={myListings} t={t} lang={lang} />
      )}

      {tab === 'wishlist' && (<>
        <div style={{ marginBottom: 16 }}>
          <h3 style={{ margin: '0 0 8px', fontSize: 16, fontWeight: 600 }}>🔔 {t.marketplaceAlerts}</h3>
          <p style={{ margin: '0 0 10px', fontSize: 13, color: '#555' }}>{t.marketplaceAlertsHint}</p>
          <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
            <input
              style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid #ccc', fontSize: 14 }}
              placeholder={t.marketplaceAlertPlaceholder}
              value={kwInput}
              onChange={e => setKwInput(e.target.value)}
              onKeyDown={e => {
                if (e.key === 'Enter' && kwInput.trim()) {
                  apiCreateMarketplaceAlert(kwInput.trim()).then(r => {
                    if (r?.ok) {
                      apiGetMarketplaceAlerts().then(d => { if (d?.alerts) setKwAlerts(d.alerts) })
                      setKwInput('')
                    }
                  })
                }
              }}
            />
            <button
              style={{ padding: '6px 14px', borderRadius: 6, background: '#2D6A4F', color: '#fff', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: 14 }}
              onClick={() => {
                if (!kwInput.trim()) return
                apiCreateMarketplaceAlert(kwInput.trim()).then(r => {
                  if (r?.ok) {
                    apiGetMarketplaceAlerts().then(d => { if (d?.alerts) setKwAlerts(d.alerts) })
                    setKwInput('')
                  }
                })
              }}
            >{t.marketplaceAlertAdd}</button>
          </div>
          {kwAlerts.length === 0 && <p style={{ margin: 0, fontSize: 13, color: '#999' }}>{t.marketplaceAlertEmpty}</p>}
          {kwAlerts.length > 0 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
              {kwAlerts.map(a => (
                <div key={a.id} style={{ display: 'flex', alignItems: 'center', gap: 8, background: '#fff', border: '1px solid #ddd', borderRadius: 8, padding: '6px 10px' }}>
                  {kwEditId === a.id ? (
                    <>
                      <input
                        style={{ flex: 1, padding: '4px 8px', borderRadius: 6, border: '1px solid #ccc', fontSize: 14 }}
                        value={kwEditVal}
                        onChange={e => setKwEditVal(e.target.value)}
                        onKeyDown={e => {
                          if (e.key === 'Enter' && kwEditVal.trim()) {
                            apiUpdateMarketplaceAlert(a.id, kwEditVal.trim()).then(r => {
                              if (r?.ok) { apiGetMarketplaceAlerts().then(d => { if (d?.alerts) setKwAlerts(d.alerts) }); setKwEditId(null) }
                            })
                          }
                        }}
                        autoFocus
                      />
                      <button onClick={() => {
                        if (!kwEditVal.trim()) return
                        apiUpdateMarketplaceAlert(a.id, kwEditVal.trim()).then(r => {
                          if (r?.ok) { apiGetMarketplaceAlerts().then(d => { if (d?.alerts) setKwAlerts(d.alerts) }); setKwEditId(null) }
                        })
                      }} style={{ background: '#2D6A4F', color: '#fff', border: 'none', borderRadius: 6, padding: '4px 10px', cursor: 'pointer', fontSize: 13, fontWeight: 600 }}>{t.marketplaceAlertSave}</button>
                    </>
                  ) : (
                    <>
                      <span style={{ flex: 1, fontSize: 14 }}>{a.keyword}</span>
                      <button onClick={() => { setKwEditId(a.id); setKwEditVal(a.keyword) }} style={{ background: 'none', border: '1px solid #ccc', borderRadius: 6, padding: '3px 8px', cursor: 'pointer', fontSize: 12, color: '#555' }}>{t.marketplaceAlertEdit}</button>
                      <button onClick={() => apiDeleteMarketplaceAlert(a.id).then(() => setKwAlerts(prev => prev.filter(x => x.id !== a.id)))} style={{ background: 'none', border: '1px solid #e57373', borderRadius: 6, padding: '3px 8px', cursor: 'pointer', fontSize: 12, color: '#e57373' }}>{t.marketplaceAlertDelete}</button>
                    </>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
        <MarketplaceWishlist lang={lang} onViewListing={(id) => {
          const l = listings.find(x => x.id === id)
          if (l) setSelectedListing(l)
          else setTab('browse')
        }} />
      </>)}

      {tab !== 'map' && tab !== 'stats' && tab !== 'wishlist' && (tab === 'mine' && myListings.length === 0 ? (
        <div className="p-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>
          <div style={{ fontSize: 36, marginBottom: 12 }}>🛍️</div>
          <div style={{ marginBottom: 16 }}>{t.marketplaceNoMyListings}</div>
          <button className="p-marketplace-create-btn" onClick={() => { setEditListing(null); setFormError(null); setShowForm(true) }}>
            {t.marketplaceCreateFirst}
          </button>
        </div>
      ) : displayListings.length === 0 ? (
        <div className="p-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>
          🔍 {t.marketplaceNoListings}
        </div>
      ) : (
        <div className="p-marketplace-grid">
            {displayListings.map(listing => (
            <div
              key={listing.id}
              className={`p-card p-listing-card${listing.sold ? ' p-listing-sold' : ''}`}
              onClick={() => { setSelectedListing(listing); if (listing.user_id !== currentUser?.id) apiRecordListingView(listing.id).catch(() => {}) }}
            >
              <div className="p-listing-photo-wrap">
                {listing.photos?.length > 0 ? (
                  <img
                    className="p-listing-photo"
                    src={listing.photos[0].url || listing.photos[0]}
                    alt=""
                    loading="lazy"
                  />
                ) : (
                  <div className="p-listing-photo-placeholder">{catIcon(listing.category)}</div>
                )}
                {!!listing.sold && <div className="p-listing-sold-badge">{t.marketplaceSold}</div>}
                {isBoosted(listing) && <div className="p-listing-sold-badge" style={{ background: '#F4A261' }}>{t.marketplaceBoosted}</div>}
              </div>
              <div className="p-listing-body">
                <div className="p-listing-price">
                  {listing.priceNegotiable
                    ? t.marketplacePriceNegotiable
                    : formatPrice(listing.price)}
                </div>
                <div className="p-listing-title">{listingTitle(listing)}</div>
                <div className="p-listing-meta">
                  <span>{catLabel(listing.category)}</span>
                  <span>📍 {listing.location}</span>
                  <span style={{ color: '#aaa', display: 'inline-flex', alignItems: 'center', gap: 4 }}>
                    {listing.seller_online ? <span style={{ width: 8, height: 8, borderRadius: '50%', background: '#22c55e', display: 'inline-block', flexShrink: 0 }} /> : null}
                    {listing.seller}
                  </span>
                </div>
                {tab === 'mine' && (() => {
                  const viewCount = marketplaceStats?.topListings?.find(l => l.id === listing.id)?.views
                  return viewCount !== undefined ? (
                    <div style={{ fontSize: 12, color: '#888', marginBottom: 4, display: 'flex', alignItems: 'center', gap: 4 }}>
                      👁 {viewCount} {t.marketplaceStatsViews}
                    </div>
                  ) : null
                })()}
                {tab === 'mine' && (
                  <div className="p-listing-actions" onClick={e => e.stopPropagation()}>
                    {!listing.sold && !isBoosted(listing) && (
                      <button className="p-listing-action-btn" style={{ color: '#F4A261', borderColor: '#F4A261' }} onClick={() => handleBoost(listing.id)}>
                        {t.marketplaceBoostBtn}
                      </button>
                    )}
                    {!listing.sold && (
                      <button className="p-listing-action-btn" onClick={() => handleMarkSold(listing.id)}>
                        ✓ {t.marketplaceMarkSold}
                      </button>
                    )}
                    {!!listing.sold && (
                      <button className="p-listing-action-btn" style={{ color: '#2D6A4F', borderColor: '#2D6A4F' }} onClick={() => handleRelist(listing.id)}>
                        ↺ {t.relist}
                      </button>
                    )}
                    <button className="p-listing-action-btn" onClick={() => { setEditListing(listing); setFormError(null); setShowForm(true) }}>
                      ✏️ {t.marketplaceEdit}
                    </button>
                    <button className="p-listing-action-btn danger" onClick={() => setDeleteConfirmId(listing.id)}>
                      🗑 {t.marketplaceDelete}
                    </button>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      ))}

      {deleteConfirmId && (
        <div className="modal-backdrop" onClick={() => setDeleteConfirmId(null)}>
          <div className="p-msg-modal" style={{ maxWidth: 360 }} onClick={e => e.stopPropagation()}>
            <div className="p-msg-modal-header">
              <span>{t.marketplaceDelete}</span>
              <button className="p-msg-modal-close" onClick={() => setDeleteConfirmId(null)}>✕</button>
            </div>
            <div style={{ padding: '16px 20px 20px' }}>
              <p style={{ margin: '0 0 16px', fontSize: 14, color: '#555' }}>{t.marketplaceDeleteConfirm}</p>
              <div style={{ display: 'flex', gap: 8 }}>
                <button className="p-msg-modal-btn secondary" onClick={() => setDeleteConfirmId(null)}>{t.marketplaceCancel}</button>
                <button className="p-msg-modal-btn primary" style={{ background: '#C0392B' }} onClick={() => handleDelete(deleteConfirmId)}>
                  {t.marketplaceDelete}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {selectedListing && (
        <ListingDetailModal
          listing={selectedListing}
          t={t}
          lang={lang}
          currentUser={currentUser}
          catLabel={catLabel}
          catIcon={catIcon}
          listingTitle={listingTitle}
          listingDesc={listingDesc}
          onClose={() => setSelectedListing(null)}
          onContactSeller={onContactSeller}
          onViewProfile={onViewProfile}
          onEdit={() => {
            setEditListing(selectedListing)
            setFormError(null)
            setShowForm(true)
            setSelectedListing(null)
          }}
          onMarkSold={async () => {
            await handleMarkSold(selectedListing.id)
            setSelectedListing(null) // close modal — listing disappears from browse
          }}
          onMakeOffer={onMakeOffer}
        />
      )}

      {showForm && (
        <ListingFormModal
          t={t}
          lang={lang}
          listing={editListing}
          listingTitle={listingTitle}
          listingDesc={listingDesc}
          formError={formError}
          maxPhotos={maxPhotos}
          currentUser={currentUser}
          onClose={() => { setShowForm(false); setEditListing(null); setFormError(null) }}
          onSubmit={editListing ? handleUpdate : handleCreate}
        />
      )}
    </div>
  )
}

function ListingDetailModal({ listing, t, lang, currentUser, catLabel, catIcon, listingTitle, listingDesc, onClose, onContactSeller, onViewProfile, onEdit, onMarkSold, onMakeOffer }) {
  useEffect(() => {
    const handler = (e) => { if (e.key === 'Escape') onClose() }
    document.addEventListener('keydown', handler)
    return () => document.removeEventListener('keydown', handler)
  }, [onClose])

  const isOwn = (typeof listing.sellerId === 'number' && listing.sellerId > 0)
    ? listing.sellerId === currentUser?.id
    : listing.seller === currentUser?.name

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="p-listing-detail-modal" onClick={e => e.stopPropagation()}>
        <div className="p-listing-detail-close-wrap">
          <button className="p-listing-detail-close" onClick={onClose}>✕</button>
        </div>
        {listing.photos?.length > 0 ? (
          <div className={`p-post-media p-post-media-${Math.min(listing.photos.length, 4)} p-listing-detail-photos`}>
            {listing.photos.slice(0, 4).map((p, i) => (
              <img key={i} className="p-media-item" src={p.url || p} alt="" loading="lazy" />
            ))}
          </div>
        ) : (
          <div className="p-listing-detail-no-photo">
            <span style={{ fontSize: 56 }}>{catIcon(listing.category)}</span>
          </div>
        )}
        <div className="p-listing-detail-body">
          {listing.sold ? <div className="p-listing-sold-badge p-listing-sold-badge-lg">{t.marketplaceSold}</div> : null}
          {!listing.sold && listing.boosted_until && new Date(listing.boosted_until) > new Date() ? <div className="p-listing-sold-badge p-listing-sold-badge-lg" style={{ background: '#F4A261' }}>{t.marketplaceBoosted}</div> : null}
          <div className="p-listing-detail-price">
            {listing.priceNegotiable
              ? t.marketplacePriceNegotiable
              : `${listing.price.toLocaleString()} ${t.dKK}`}
          </div>
          <h2 className="p-listing-detail-title">{listingTitle(listing)}</h2>
          <div className="p-listing-detail-meta">
            <span>{catLabel(listing.category)}</span>
            <span>📍 {listing.location}</span>
            {listing.postedAt && <span>📅 {listing.postedAt}</span>}
          </div>
          {/* Seller info */}
          <div
            style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '10px 12px', background: '#F7F5F2', borderRadius: 10, marginTop: 10, cursor: (!isOwn && typeof listing.sellerId === 'number' && listing.sellerId > 0 && onViewProfile) ? 'pointer' : 'default' }}
            onClick={() => { if (!isOwn && typeof listing.sellerId === 'number' && listing.sellerId > 0 && onViewProfile) onViewProfile(listing.sellerId) }}
          >
            <div style={{ width: 38, height: 38, borderRadius: '50%', background: '#2D6A4F', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, fontSize: 16, flexShrink: 0 }}>
              {listing.seller?.[0]?.toUpperCase() || '?'}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontWeight: 600, fontSize: 14, color: '#1A1A1A' }}>{listing.seller}</div>
              <div style={{ fontSize: 12, color: '#aaa' }}>{t.marketplacePostedBy}{listing.postedAt ? ` · ${listing.postedAt}` : ''}</div>
            </div>
            {!isOwn && typeof listing.sellerId === 'number' && listing.sellerId > 0 && onViewProfile && (
              <span style={{ fontSize: 12, color: '#1877F2', fontWeight: 500, whiteSpace: 'nowrap' }}>
                {t.viewProfile2}
              </span>
            )}
          </div>
          {listingDesc(listing) && <p className="p-listing-detail-desc">{listingDesc(listing)}</p>}

          {listing.location && (
            <div style={{ marginTop: 12 }}>
              <OsmMap location={listing.location} height={200} lang={lang} />
            </div>
          )}

          {/* Owner actions */}
          {isOwn && (
            <div style={{ display: 'flex', gap: 8, marginTop: 12, flexWrap: 'wrap' }}>
              <button
                className="p-marketplace-create-btn"
                style={{ flex: 1, justifyContent: 'center', background: '#fff', color: '#2D6A4F', border: '1.5px solid #2D6A4F' }}
                onClick={() => { onEdit?.(); }}
              >
                ✏️ {t.adminModKeywordEdit}
              </button>
              {!listing.sold && (
                <button
                  className="p-marketplace-create-btn"
                  style={{ flex: 1, justifyContent: 'center', background: '#fff', color: '#E07B39', border: '1.5px solid #E07B39' }}
                  onClick={() => { onMarkSold?.(); }}
                >
                  ✅ {t.markAsSold}
                </button>
              )}
            </div>
          )}

          {/* Contact section */}
          {!listing.sold && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 12 }}>
              {/* Send message button — only for other users */}
              {!isOwn && (
                typeof listing.sellerId === 'number' && listing.sellerId > 0 ? (
                  <>
                    <button
                      className="p-marketplace-create-btn"
                      style={{ width: '100%', justifyContent: 'center' }}
                      onClick={() => { onContactSeller(listing.sellerId); onClose() }}
                    >
                      💬 {t.marketplaceContactSeller}
                    </button>
                    {!listing.sold && (
                      <button
                        style={{ width: '100%', padding: '11px', borderRadius: 10, border: '2px solid #1877F2', background: 'transparent', color: '#1877F2', fontWeight: 700, fontSize: 15, cursor: 'pointer', marginTop: 8 }}
                        onClick={() => { onMakeOffer?.(listing); onClose() }}
                      >
                        💸 {t.makeAnOffer}
                      </button>
                    )}
                    <button
                      style={{ width: '100%', padding: '9px', borderRadius: 10, border: '1px solid var(--border,#ddd)', background: 'transparent', color: '#888', fontSize: 14, cursor: 'pointer', marginTop: 6 }}
                      onClick={async () => {
                        if (listing._saved) { await apiUnsaveListing(listing.id); listing._saved = false }
                        else { await apiSaveListing(listing.id); listing._saved = true }
                        onClose()
                      }}
                    >
                      {listing._saved ? '🔖 ' : '📌 '}{t.saveToWishlist}
                    </button>
                  </>
                ) : (
                  <div style={{ textAlign: 'center', color: '#aaa', fontSize: 13, padding: '4px 0' }}>
                    {t.sellerIsNotOnFellis}
                  </div>
                )
              )}
              {/* Contact info — shown for everyone when populated */}
              {(listing.mobilepay || listing.contact_phone || listing.contact_email) && (
                <div style={{ borderTop: isOwn ? 'none' : '1px solid #f0ebe5', paddingTop: isOwn ? 0 : 8, display: 'flex', flexDirection: 'column', gap: 6 }}>
                  {isOwn && (
                    <div style={{ fontSize: 11, color: '#aaa', marginBottom: 2 }}>
                      {t.yourContactInfoOnThisListing}
                    </div>
                  )}
                  {listing.mobilepay && (
                    <a href={`mobilepay://send?phone=${listing.mobilepay}`}
                      style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, padding: '10px 16px', borderRadius: 8, border: '2px solid #5A78FF', color: '#5A78FF', fontWeight: 700, fontSize: 14, textDecoration: 'none', background: '#fff' }}>
                      📱 MobilePay · {listing.mobilepay}
                    </a>
                  )}
                  {listing.contact_phone && (
                    <a href={`tel:${listing.contact_phone}`}
                      style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, padding: '10px 16px', borderRadius: 8, border: '1.5px solid #ddd', color: '#333', fontWeight: 600, fontSize: 14, textDecoration: 'none', background: '#fff' }}>
                      📞 {listing.contact_phone}
                    </a>
                  )}
                  {listing.contact_email && (
                    <a href={`mailto:${listing.contact_email}`}
                      style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, padding: '10px 16px', borderRadius: 8, border: '1.5px solid #ddd', color: '#333', fontWeight: 600, fontSize: 14, textDecoration: 'none', background: '#fff' }}>
                      ✉️ {listing.contact_email}
                    </a>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

function ListingFormModal({ t, lang, listing, listingTitle, listingDesc, formError, maxPhotos = 4, currentUser, onClose, onSubmit }) {
  const isEdit = !!listing
  const sanitize = (v) => (!v || v === '[object Object]') ? '' : v
  // For new listings prefill contact fields from the current user's profile so
  // they don't have to retype the same MobilePay/phone/email on every listing.
  // MobilePay falls back to the phone number (many DK users reuse it).
  const userMobilepay = currentUser?.mobilepay || (currentUser?.phone ? String(currentUser.phone).replace(/\D/g, '').slice(-8) : '')
  const userPhone = currentUser?.phone || ''
  const userEmail = currentUser?.email || ''
  const [title, setTitle]           = useState(isEdit ? sanitize(listingTitle(listing)) : '')
  const [price, setPrice]           = useState(isEdit ? (listing.price || '') : '')
  const [negotiable, setNegotiable] = useState(isEdit ? !!listing.priceNegotiable : false)
  const [category, setCategory]     = useState(isEdit ? (listing.category || '') : '')
  const [subcategory, setSubcategory] = useState(isEdit ? (listing.subcategory || '') : '')
  const [catTree, setCatTree] = useState(null) // null = loading; array = loaded (possibly empty)
  useEffect(() => {
    let cancelled = false
    apiGetMarketplaceCategories().then(data => {
      if (cancelled) return
      setCatTree(Array.isArray(data?.categories) ? data.categories : [])
    })
    return () => { cancelled = true }
  }, [])
  // Fall back to hardcoded list while API loads (or if it returns empty)
  const categoryOptions = (catTree && catTree.length > 0)
    ? catTree.map(c => ({ key: c.id, icon: c.icon, label: c[lang] || c.da, subs: c.subcategories || [] }))
    : MARKETPLACE_CATEGORIES.map(c => ({ key: c.key, icon: c.icon, label: t[c.labelKey], subs: [] }))
  const currentCat = categoryOptions.find(c => c.key === category)
  const subcategoryOptions = currentCat?.subs || []
  const [location, setLocation]     = useState(isEdit ? (listing.location || '') : '')
  const [description, setDescription] = useState(isEdit ? sanitize(listingDesc(listing)) : '')
  const [mobilepay, setMobilepay]   = useState(isEdit ? (listing.mobilepay || '') : userMobilepay)
  const [phone, setPhone]           = useState(isEdit ? (listing.contact_phone || '') : userPhone)
  const [contactEmail, setContactEmail] = useState(isEdit ? (listing.contact_email || '') : userEmail)
  const [photoFiles, setPhotoFiles] = useState([])
  const [photoPreviews, setPhotoPreviews] = useState(
    isEdit ? (listing.photos || []).map(p => p.url || p) : []
  )
  const addFiles = (files) => {
    const toAdd = Array.from(files).filter(f => f.type.startsWith('image/')).slice(0, maxPhotos - photoPreviews.length)
    if (!toAdd.length) return
    setPhotoFiles(prev => [...prev, ...toAdd].slice(0, maxPhotos))
    setPhotoPreviews(prev => [...prev, ...toAdd.map(f => URL.createObjectURL(f))].slice(0, maxPhotos))
  }

  const handlePaste = (e) => {
    const items = Array.from(e.clipboardData?.items || [])
    const imageFiles = items.filter(i => i.kind === 'file' && i.type.startsWith('image/')).map(i => i.getAsFile())
    if (imageFiles.length) { e.preventDefault(); addFiles(imageFiles) }
  }

  const removePhoto = (i) => {
    const url = photoPreviews[i]
    setPhotoPreviews(prev => prev.filter((_, idx) => idx !== i))
    if (url?.startsWith('blob:')) {
      // photoFiles only holds NEW files; find this file's index by counting blob URLs before i
      const fileIdx = photoPreviews.slice(0, i).filter(u => u.startsWith('blob:')).length
      setPhotoFiles(prev => prev.filter((_, idx) => idx !== fileIdx))
    }
  }

  const handleSubmit = (e) => {
    e.preventDefault()
    if (!title.trim() || (!negotiable && !price) || !category || !location.trim()) return
    const localListing = {
      title: { da: title, en: title },
      price: negotiable ? 0 : Number(price),
      priceNegotiable: negotiable,
      category,
      subcategory: subcategory || null,
      location,
      description: { da: description, en: description },
      photos: photoPreviews.map(url => ({ url })),
      mobilepay: mobilepay.trim() || null,
      contact_phone: phone.trim() || null,
      contact_email: contactEmail.trim() || null,
    }
    const formData = new FormData()
    formData.append('title', title)
    formData.append('price', negotiable ? 0 : price)
    formData.append('priceNegotiable', negotiable)
    formData.append('category', category)
    if (subcategory) formData.append('subcategory', subcategory)
    formData.append('location', location)
    formData.append('description', description)
    if (mobilepay.trim()) formData.append('mobilepay', mobilepay.trim())
    if (phone.trim()) formData.append('contact_phone', phone.trim())
    if (contactEmail.trim()) formData.append('contact_email', contactEmail.trim())
    if (isEdit) {
      // Tell server which existing photos to keep — append BEFORE file uploads so multer parses it first
      const existingPhotos = photoPreviews
        .filter(url => !url.startsWith('blob:'))
        .map(url => ({ url, type: 'image' }))
      formData.append('existingPhotos', JSON.stringify(existingPhotos))
    }
    photoFiles.forEach(f => formData.append('photos', f))
    if (isEdit) {
      onSubmit(listing.id, formData, localListing)
    } else {
      onSubmit(formData, localListing)
    }
  }

  const fS = { width: '100%', padding: '8px 10px', border: '1px solid #E8E4DF', borderRadius: 8, fontSize: 14, fontFamily: 'inherit', boxSizing: 'border-box', marginBottom: 12 }
  const lS = { fontSize: 13, fontWeight: 600, color: '#555', marginBottom: 4, display: 'block' }

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="p-listing-form-modal" onClick={e => e.stopPropagation()}>
        <div className="p-msg-modal-header">
          <span>{isEdit ? t.marketplaceEditTitle : t.marketplaceFormTitle}</span>
          <button className="p-msg-modal-close" onClick={onClose}>✕</button>
        </div>
        <form onSubmit={handleSubmit} onPaste={handlePaste} style={{ padding: '16px 20px 20px', overflowY: 'auto', maxHeight: 'calc(90vh - 60px)' }}>
          <label style={lS}>{t.marketplaceFieldTitle}</label>
          <input style={fS} value={title} onChange={e => setTitle(e.target.value)} placeholder={t.whatAreYouSelling} required />

          <label style={lS}>{t.marketplaceFieldCategory}</label>
          <select
            style={fS}
            value={category}
            onChange={e => { setCategory(e.target.value); setSubcategory('') }}
            required
          >
            <option value="">{t.chooseCategory}</option>
            {categoryOptions.map(c => (
              <option key={c.key} value={c.key}>{c.icon} {c.label}</option>
            ))}
          </select>

          {subcategoryOptions.length > 0 && (
            <>
              <label style={lS}>{t.marketplaceFieldSubcategory}</label>
              <select
                style={fS}
                value={subcategory}
                onChange={e => setSubcategory(e.target.value)}
              >
                <option value="">{t.chooseSubcategoryOptional}</option>
                {subcategoryOptions.map(s => (
                  <option key={s.id} value={s.id}>{s.icon} {s[lang] || s.da}</option>
                ))}
              </select>
            </>
          )}

          <label style={lS}>{t.marketplaceFieldPrice}</label>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center', marginBottom: 12 }}>
            <input
              style={{ ...fS, marginBottom: 0, flex: 1 }}
              type="number"
              min="0"
              value={price}
              onChange={e => setPrice(e.target.value)}
              placeholder={t.eG500}
              disabled={negotiable}
              required={!negotiable}
            />
            <label style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 13, whiteSpace: 'nowrap', cursor: 'pointer', flexShrink: 0 }}>
              <input type="checkbox" checked={negotiable} onChange={e => setNegotiable(e.target.checked)} />
              {t.marketplaceFieldNegotiable}
            </label>
          </div>

          <label style={lS}>{t.marketplaceFieldLocation}</label>
          <LocationAutocomplete
            value={location}
            onChange={setLocation}
            onSelect={loc => loc && setLocation(loc.name)}
            lang={lang}
            placeholder={t.eGNørrebroCopenhagen}
            required
            inputStyle={fS}
          />

          <div style={{ marginTop: 8, marginBottom: 4 }}>
            <label style={lS}>{t.extraContactOptionsOptional}</label>
            <div style={{ fontSize: 11, color: '#888', marginTop: 2 }}>
              {t.fellisMessagesIsTheDefaultAddExtraOptionsBelowIfDe}
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
            <span style={{ fontSize: 18, flexShrink: 0 }}>📱</span>
            <input style={{ ...fS, marginBottom: 0, flex: 1 }} value={mobilepay} onChange={e => setMobilepay(e.target.value.replace(/\D/g, '').slice(0, 8))} placeholder={t.mobilePayEG20123456} maxLength={8} inputMode="numeric" />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
            <span style={{ fontSize: 18, flexShrink: 0 }}>📞</span>
            <input style={{ ...fS, marginBottom: 0, flex: 1 }} value={phone} onChange={e => setPhone(e.target.value)} placeholder={t.phoneNumberOptional} inputMode="tel" />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
            <span style={{ fontSize: 18, flexShrink: 0 }}>✉️</span>
            <input style={{ ...fS, marginBottom: 0, flex: 1 }} value={contactEmail} onChange={e => setContactEmail(e.target.value)} placeholder={t.emailAddressOptional} type="email" autoComplete="email" />
          </div>

          <label style={lS}>{t.marketplaceFieldDescription}</label>
          <textarea style={{ ...fS, minHeight: 80, resize: 'vertical' }} value={description} onChange={e => setDescription(e.target.value)} placeholder={t.describeTheItem} />

          <label style={lS}>{t.marketplaceFieldPhotos} <span style={{ fontWeight: 400, color: '#999' }}>({`${t.maxPhotosPrefix}${maxPhotos}`})</span></label>
          <div className="p-listing-photo-upload-row">
            {photoPreviews.map((src, i) => (
              <div key={i} className="p-listing-upload-thumb">
                <img src={src} alt="" />
                <button type="button" className="p-listing-upload-remove" onClick={() => removePhoto(i)}>✕</button>
              </div>
            ))}
            {photoPreviews.length < maxPhotos && (
              <MediaPickerButton
                lang={lang}
                accept="image/*"
                onFiles={addFiles}
                buttonContent={<><span>📷</span><span style={{ fontSize: 11, marginTop: 2 }}>{t.addPhoto}</span></>}
              />
            )}
          </div>
          {photoPreviews.length < maxPhotos && (
            <div style={{ fontSize: 11, color: '#aaa', marginTop: 4 }}>
              {t.youCanAlsoPasteImagesWithCtrlV}
            </div>
          )}

          {formError && (
            <div style={{ background: '#fff0f0', border: '1px solid #f5c6c6', borderRadius: 8, padding: '10px 14px', marginTop: 12, fontSize: 13, color: '#c0392b' }}>
              ⚠️ {formError}
            </div>
          )}
          <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
            <button type="button" onClick={onClose} style={{ flex: 1, padding: 10, borderRadius: 8, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 14 }}>{t.marketplaceCancel}</button>
            <button type="submit" style={{ flex: 2, padding: 10, borderRadius: 8, border: 'none', background: '#2D6A4F', color: '#fff', cursor: 'pointer', fontSize: 14, fontWeight: 700 }}>
              {isEdit ? t.marketplaceSaveEdit : t.marketplacePublish}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

