function WelcomeOnboardingModal({ lang, inviterName, onDone }) {
  const da = lang === 'da'
  // step -1 = welcome, 0..4 = feature steps, 5 = benefits
  const [step, setStep] = useState(-1)
  const totalFeatureSteps = ONBOARDING_STEPS.length
  const isWelcome = step === -1
  const isBenefits = step === totalFeatureSteps
  const isLastFeature = step === totalFeatureSteps - 1
  const cur = step >= 0 && !isBenefits ? ONBOARDING_STEPS[step] : null

  const next = () => setStep(s => s + 1)

  return (
    <div className="modal-backdrop" style={{ zIndex: 3000 }} onClick={e => e.stopPropagation()}>
      <div style={{ background: '#fff', borderRadius: 18, maxWidth: 440, width: '90%', padding: '32px 28px 24px', position: 'relative', boxShadow: '0 8px 40px rgba(0,0,0,0.18)', textAlign: 'center' }}>
        {/* Skip / close */}
        <button
          onClick={onDone}
          style={{ position: 'absolute', top: 14, right: 16, background: 'none', border: 'none', cursor: 'pointer', fontSize: 20, color: '#bbb', lineHeight: 1 }}
          aria-label="Luk"
        >✕</button>

        {isWelcome && (
          <>
            <div style={{ fontSize: 56, marginBottom: 12 }}>🎉</div>
            <h2 style={{ margin: '0 0 8px', fontSize: 22, fontWeight: 800, color: '#1A1A1A' }}>
              {da ? 'Velkommen til Fellis.eu!' : 'Welcome to Fellis.eu!'}
            </h2>
            {inviterName && (
              <div style={{ margin: '0 0 12px', padding: '10px 16px', background: '#F0FAF4', borderRadius: 10, fontSize: 14, color: '#2D6A4F', fontWeight: 600 }}>
                🤝 {da ? `Du er inviteret af ${inviterName} — I er nu forbundet!` : `You were invited by ${inviterName} — you are now connected!`}
              </div>
            )}
            <p style={{ margin: '0 0 24px', fontSize: 14, color: '#666', lineHeight: 1.6 }}>
              {da
                ? 'Fellis er den danske, private platform uden annoncører. Lad os vise dig rundt på få sekunder.'
                : 'Fellis is the Danish, private platform without advertisers. Let us show you around in a few seconds.'}
            </p>
            <button
              className="p-btn-primary"
              style={{ width: '100%', padding: '12px 0', fontSize: 15, borderRadius: 10 }}
              onClick={next}
            >
              {da ? 'Kom i gang →' : 'Get started →'}
            </button>
          </>
        )}

        {cur && (
          <>
            {/* Progress dots */}
            <div style={{ display: 'flex', justifyContent: 'center', gap: 6, marginBottom: 20 }}>
              {ONBOARDING_STEPS.map((_, i) => (
                <div key={i} style={{ width: 7, height: 7, borderRadius: '50%', background: i === step ? '#2D6A4F' : '#E8E4DF', transition: 'background 0.2s' }} />
              ))}
            </div>
            <div style={{ fontSize: 52, marginBottom: 12 }}>{cur.icon}</div>
            <h3 style={{ margin: '0 0 10px', fontSize: 20, fontWeight: 700, color: '#1A1A1A' }}>{cur.title[lang] || cur.title.da}</h3>
            <p style={{ margin: '0 0 28px', fontSize: 14, color: '#666', lineHeight: 1.6 }}>{cur.desc[lang] || cur.desc.da}</p>
            <div style={{ display: 'flex', gap: 8 }}>
              <button
                onClick={() => setStep(s => s - 1)}
                style={{ flex: 1, padding: '11px 0', borderRadius: 10, border: '1.5px solid #E8E4DF', background: '#fff', fontSize: 14, cursor: 'pointer', color: '#555', fontWeight: 600 }}
              >
                ← {da ? 'Forrige' : 'Back'}
              </button>
              <button
                className="p-btn-primary"
                style={{ flex: 2, padding: '11px 0', fontSize: 15, borderRadius: 10 }}
                onClick={next}
              >
                {isLastFeature ? (da ? 'Se fordele →' : 'See benefits →') : (da ? 'Næste →' : 'Next →')}
              </button>
            </div>
          </>
        )}

        {isBenefits && (
          <>
            <div style={{ fontSize: 48, marginBottom: 12 }}>✨</div>
            <h3 style={{ margin: '0 0 16px', fontSize: 20, fontWeight: 800, color: '#1A1A1A' }}>
              {da ? 'Hvorfor Fellis.eu?' : 'Why Fellis.eu?'}
            </h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 24, textAlign: 'left' }}>
              {[
                { icon: '🔒', da: 'Privat by design — dine data sælges aldrig', en: 'Private by design — your data is never sold' },
                { icon: '🇪🇺', da: 'Hostet i EU — GDPR-godkendt fra dag ét', en: 'Hosted in the EU — GDPR-compliant from day one' },
                { icon: '🚫', da: 'Ingen annoncører eller algoritme-manipulation', en: 'No advertisers or algorithmic manipulation' },
                { icon: '🌱', da: 'Dansk platform bygget til fællesskab', en: 'Danish platform built for community' },
                { icon: '🗑️', da: 'Slet alt dine data med ét klik til enhver tid', en: 'Delete all your data with one click at any time' },
              ].map(({ icon, da: textDa, en: textEn }) => (
                <div key={icon} style={{ display: 'flex', alignItems: 'flex-start', gap: 10, padding: '8px 12px', background: '#F7F5F2', borderRadius: 8, fontSize: 13, color: '#333' }}>
                  <span style={{ fontSize: 18, flexShrink: 0 }}>{icon}</span>
                  <span>{da ? textDa : textEn}</span>
                </div>
              ))}
            </div>
            <button
              className="p-btn-primary"
              style={{ width: '100%', padding: '13px 0', fontSize: 15, borderRadius: 10 }}
              onClick={onDone}
            >
              {da ? '🚀 Kom i gang!' : '🚀 Let\'s go!'}
            </button>
          </>
        )}
      </div>
    </div>
  )
}

function UpgradeModal({ lang, t, onUpgrade, onClose }) {
  const features = lang === 'da'
    ? ['Målgruppeindsigt & demografi', 'Indholdsanalyse & trends', 'Virksomhedsside-statistik', 'Forbindelsestragt', 'Branche-benchmarking', 'CSV / PDF export', 'Datointerval-selector']
    : ['Audience insights & demographics', 'Content analysis & trends', 'Company page statistics', 'Connection funnel', 'Industry benchmarking', 'CSV / PDF export', 'Date range selector']
  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="p-upgrade-modal" onClick={e => e.stopPropagation()}>
        <div className="p-upgrade-modal-header">
          <span className="p-upgrade-plan-badge">{t.analyticsPlanBadge}</span>
          <button className="p-upgrade-modal-close" onClick={onClose}>✕</button>
        </div>
        <h2 className="p-upgrade-modal-title">{t.analyticsUpgradeTitle}</h2>
        <p className="p-upgrade-modal-desc">{t.analyticsUpgradeDesc}</p>
        <ul className="p-upgrade-features">
          {features.map((f, i) => <li key={i}>✓ {f}</li>)}
        </ul>
        <button className="p-upgrade-btn" onClick={onUpgrade}>{t.analyticsUpgradeBtn}</button>
        <button className="p-upgrade-cancel" onClick={onClose}>{t.analyticsUpgradeCancel}</button>
      </div>
    </div>
  )
}

// ─────────────────────────────────────────────
// ── AnalyticsPage ─────────────────────────────
// ─────────────────────────────────────────────

const ANALYTICS_RANGES = [7, 30, 90]

function AnalyticsPage({ lang, t, currentUser, onNavigate }) {
  const navigateTo = onNavigate || (() => {})
  const [range, setRange] = useState(30)
  const [analytics, setAnalytics] = useState(null)

  useEffect(() => {
    setAnalytics(null)
    apiGetAnalytics(range).then(data => setAnalytics(data)).catch(() => {})
  }, [range])

  // Convert sparse {date, count} rows into a dense array covering the last `days` days
  const fillDays = useCallback((rows, days) => {
    const map = {}
    ;(rows || []).forEach(r => { map[(r.date || '').slice(0, 10)] = Number(r.count) })
    return Array.from({ length: days }, (_, i) => {
      const d = new Date(); d.setDate(d.getDate() - (days - 1 - i))
      return map[d.toISOString().slice(0, 10)] || 0
    })
  }, [])

  // ── Time series ── (real when loaded, seeded fallback while loading)
  const profileViews = analytics ? fillDays(analytics.views, range) : genViews(range, 0, 999)
  const connViews    = analytics ? fillDays(analytics.connections, range) : genViews(range, 0, 777)
  const engTrend     = analytics ? fillDays(analytics.engTrend, range) : genViews(range, 0, 333)

  const totalViews = profileViews.reduce((a, b) => a + b, 0)
  const totalConns = connViews.reduce((a, b) => a + b, 0)

  const eng = analytics?.engagement
  const avgEngRate = eng
    ? (eng.posts > 0 ? ((eng.likes + eng.comments) / eng.posts).toFixed(1) : '0.0')
    : '–'

  // Top posts: real data; empty-state message when user has no posts yet
  const topPosts = analytics?.topPosts?.length
    ? analytics.topPosts
    : analytics
      ? [{ label: t.noPostsYet, value: 0 }]
      : [{ label: '…', value: 0 }]

  // ── Funnel (real) ──
  const fv = analytics?.funnel
  const funnelViews = fv ? fv.views : totalViews
  const funnelReqs  = fv ? fv.requests : 0
  const funnelConns = fv ? fv.connections : 0
  const maxF = Math.max(funnelViews, 1)
  const funnelData = [
    { label: t.analyticsFunnelViews,    value: funnelViews, pct: 100 },
    { label: t.analyticsFunnelRequests, value: funnelReqs,  pct: Math.max(funnelReqs > 0 ? Math.round((funnelReqs / maxF) * 100) : 0, funnelReqs > 0 ? 8 : 0) },
    { label: t.analyticsFunnelAccepted, value: funnelConns, pct: Math.max(funnelConns > 0 ? Math.round((funnelConns / maxF) * 100) : 0, funnelConns > 0 ? 4 : 0) },
  ]

  // ── Post types (real) ──
  const pt = analytics?.postTypes
  const postTypeItems = pt && (pt.text + pt.media) > 0
    ? [
        { label: t.text, value: pt.text },
        { label: t.media, value: pt.media },
      ].filter(i => i.value > 0)
    : [
        { label: t.text, value: 6.1 },
        { label: t.image, value: 8.4 },
        { label: t.video, value: 11.2 },
      ]

  // ── Audience demographics — from real API data ──
  const industryData = analytics?.industryDist?.length
    ? analytics.industryDist.map(d => ({ label: d.label, value: d.pct }))
    : null

  const cityData = analytics?.audienceLocations?.length
    ? analytics.audienceLocations.map(d => ({ label: d.label, value: d.pct }))
    : null

  const seniorityData = analytics?.seniorityDist?.length
    ? analytics.seniorityDist.map(d => ({ label: d.label, value: d.pct }))
    : null

  const gs = analytics?.growthSource
  const growthSource = gs && gs.total > 0
    ? [
        gs.organic > 0 && { label: t.organic, value: gs.organic },
        gs.viaInvite > 0 && { label: t.viaInvites, value: gs.viaInvite },
      ].filter(Boolean)
    : null

  const topics = analytics?.hashtagPerformance?.length
    ? analytics.hashtagPerformance
    : null

  // Competitor benchmarking: user's avg daily conn growth vs platform avg
  const platformAvg = analytics?.platformAvgConnGrowth
  const userAvgDaily = totalConns > 0 ? (totalConns / range) : 0
  const platformAvgDaily = platformAvg?.length
    ? platformAvg.reduce((s, r) => s + r.value, 0) / platformAvg.length
    : null
  const competitors = platformAvgDaily !== null
    ? [
        { label: t.youDailyAvg, value: Math.round(userAvgDaily * 10) / 10 },
        { label: t.platformAverage, value: Math.round(platformAvgDaily * 10) / 10 },
      ]
    : null

  // Total connections (real)
  const totalConnectionsVal = analytics?.totalConnections ?? currentUser?.friendCount ?? 0

  function exportCSV() {
    const rows = [['Date', 'Profile Views', 'New Connections']]
    const today = new Date()
    profileViews.forEach((v, i) => {
      const d = new Date(today); d.setDate(today.getDate() - (profileViews.length - 1 - i))
      rows.push([d.toISOString().slice(0, 10), v, connViews[i]])
    })
    const csv = rows.map(r => r.join(',')).join('\n')
    const blob = new Blob([csv], { type: 'text/csv' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a'); a.href = url; a.download = `fellis-analytics-${range}d.csv`; a.click()
    URL.revokeObjectURL(url)
  }

  return (
    <div className="p-analytics">
      {/* Header */}
      <div className="p-analytics-header">
        <h2 className="p-analytics-title">{t.analyticsTitle}</h2>
        <div className="p-analytics-controls">
          <div className="p-analytics-range-tabs">
            {ANALYTICS_RANGES.map(r => (
              <button key={r} className={`p-analytics-range-btn${range === r ? ' active' : ''}`} onClick={() => setRange(r)}>
                {r === 7 ? t.analyticsRange7 : r === 30 ? t.analyticsRange30 : t.analyticsRange90}
              </button>
            ))}
          </div>
          <div className="p-analytics-export-btns">
            <button className="p-analytics-export-btn" onClick={exportCSV}>{t.analyticsExportCSV}</button>
          </div>
        </div>
      </div>

      {/* ── Free tier ── */}
      <div className="p-analytics-section">
        <div className="p-analytics-section-title">{t.analyticsProfileViews}</div>
        <div className="p-analytics-stat-row">
          <StatCard label={t.analyticsProfileViews} value={totalViews.toLocaleString()} sub={`${range}d`} color="#1877F2" />
          <StatCard label={t.analyticsFollowerGrowth} value={totalConns > 0 ? `+${totalConns}` : '0'} sub={`${range}d`} color="#2D6A4F" />
          <StatCard label={t.analyticsEngRate} value={avgEngRate} color="#F4A261" />
        </div>
        <div className="p-analytics-chart-wrap">
          <MiniLineChart data={profileViews} color="#1877F2" height={100} />
        </div>
      </div>

      <div className="p-analytics-section">
        <div className="p-analytics-section-title">{t.analyticsTopPosts}</div>
        <HBarChart items={topPosts} color="#1877F2" />
      </div>

      {/* ── Advanced analytics — available for all business users ── */}
      <div>
        <div className="p-analytics-section">
          <div className="p-analytics-section-title">{t.analyticsAudienceTitle}</div>
          <div className="p-analytics-subsection-grid">
            <div>
              <div className="p-analytics-subsection-label">{t.analyticsAudienceIndustry}</div>
              {industryData
                ? <HBarChart items={industryData} color="#1877F2" />
                : <p style={{ fontSize: 12, color: '#aaa', margin: 0 }}>{analytics ? (t.noDataYet) : '…'}</p>}
            </div>
            <div>
              <div className="p-analytics-subsection-label">{t.analyticsAudienceCities}</div>
              {cityData
                ? <HBarChart items={cityData} color="#2D6A4F" />
                : <p style={{ fontSize: 12, color: '#aaa', margin: 0 }}>{analytics ? (t.noDataYet) : '…'}</p>}
            </div>
          </div>
          <div className="p-analytics-subsection-grid" style={{ marginTop: 16 }}>
            <div>
              <div className="p-analytics-subsection-label">{t.analyticsAudienceSeniority}</div>
              {seniorityData
                ? <HBarChart items={seniorityData} color="#F4A261" />
                : <p style={{ fontSize: 12, color: '#aaa', margin: 0 }}>{analytics ? (t.noDataYet) : '…'}</p>}
            </div>
            <div>
              <div className="p-analytics-subsection-label">{t.analyticsAudienceGrowthSource}</div>
              {growthSource
                ? <HBarChart items={growthSource} color="#7E57C2" />
                : <p style={{ fontSize: 12, color: '#aaa', margin: 0 }}>{analytics ? (t.noDataYet) : '…'}</p>}
            </div>
          </div>
          <div style={{ marginTop: 20 }}>
            <div className="p-analytics-subsection-label">{t.analyticsAudienceBestTime}</div>
            <HeatmapGrid lang={lang} data={analytics?.heatmap || null} />
          </div>
        </div>

        <div className="p-analytics-section">
          <div className="p-analytics-section-title">{t.analyticsContentTitle}</div>
          <div className="p-analytics-subsection-label">{t.analyticsContentPostType}</div>
          <HBarChart items={postTypeItems} color="#1877F2" />
          <div className="p-analytics-subsection-label" style={{ marginTop: 16 }}>{t.analyticsContentTopics}</div>
          {topics
            ? <HBarChart items={topics} color="#F4A261" />
            : <p style={{ fontSize: 12, color: '#aaa', margin: 0 }}>{analytics ? (t.noDataYetUseHashtagsInYourPosts) : '…'}</p>}
          <div className="p-analytics-subsection-label" style={{ marginTop: 16 }}>{t.analyticsContentEngTrend}</div>
          <div className="p-analytics-chart-wrap">
            <MiniLineChart data={engTrend.some(v => v > 0) ? engTrend : null} color="#F4A261" height={80} />
          </div>
        </div>

        <div className="p-analytics-section">
          <div className="p-analytics-section-title">{t.analyticsFunnelTitle}</div>
          <div className="p-analytics-funnel">
            {funnelData.map((step, i) => (
              <div key={i} className="p-analytics-funnel-step" style={{ width: `${step.pct + 40}%` }}>
                <div className="p-analytics-funnel-bar" style={{ background: i === 0 ? '#1877F2' : i === 1 ? '#4aa3f7' : '#2D6A4F' }}>
                  <span>{step.label}</span>
                  <strong>{step.value.toLocaleString()}</strong>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="p-analytics-section">
          <div className="p-analytics-section-title">{t.analyticsCompetitorTitle}</div>
          {competitors
            ? <>
                <HBarChart items={competitors} color="#1877F2" />
                <p style={{ fontSize: 12, color: '#aaa', margin: '8px 0 0' }}>
                  {t.basedOnRealConnectionDataFromFellisEu}
                </p>
              </>
            : <p style={{ fontSize: 12, color: '#aaa', margin: 0 }}>{analytics ? (t.noDataYet) : '…'}</p>}
        </div>

        <div className="p-analytics-section">
          <div className="p-analytics-section-title">{t.analyticsCompanyTitle}</div>
          <div className="p-analytics-stat-row">
            <StatCard label={t.totalConnections} value={totalConnectionsVal.toLocaleString()} sub={t.total2} color="#1877F2" />
            <StatCard label={t.newConnections} value={totalConns > 0 ? `+${totalConns}` : '0'} sub={`${range}d`} color="#2D6A4F" />
            <StatCard label={t.postsInPeriod} value={eng?.posts ?? '–'} color="#F4A261" />
          </div>
          <div className="p-analytics-chart-wrap" style={{ marginTop: 12 }}>
            <MiniLineChart data={connViews.some(v => v > 0) ? connViews : genViews(range, 1, 555)} color="#2D6A4F" height={80} />
          </div>
        </div>

        {/* Business performance section — only shown for business mode */}
        {analytics?.businessStats && (() => {
          const bs = analytics.businessStats
          const followerGrowthData = Array.from({ length: range }, (_, i) => {
            const d = new Date(); d.setDate(d.getDate() - (range - 1 - i))
            const key = d.toISOString().slice(0, 10)
            const row = (bs.followerGrowth || []).find(r => (r.date || '').slice(0, 10) === key)
            return row ? Number(row.new_followers) : 0
          })
          const fs = bs.followerStats || {}
          const pbs = bs.postBoostStats || {}
          return (
            <>
              <div className="p-analytics-section">
                <div className="p-analytics-section-title">
                  🏢 {t.businessPerformance || (t.businessPerformance)}
                </div>
                <div className="p-analytics-stat-row">
                  <StatCard label={t.totalFollowers || (t.totalFollowers)} value={(fs.total_followers ?? bs.followerCount ?? 0).toLocaleString()} color="#4338CA" />
                  <StatCard label={`${t.newFollowers || (t.newFollowers)} (7d)`} value={(fs.new_followers_7d ?? 0).toLocaleString()} color="#2D6A4F" />
                  <StatCard label={`${t.newFollowers || (t.newFollowers)} (30d)`} value={(fs.new_followers_30d ?? 0).toLocaleString()} color="#2D6A4F" />
                  <StatCard label={t.communityScoreLabel || (t.communityScoreLabel)} value={bs.communityScore.toLocaleString()} color="#F59E0B" />
                </div>
                {followerGrowthData.some(v => v > 0) && (
                  <div className="p-analytics-chart-wrap" style={{ marginTop: 12 }}>
                    <MiniLineChart data={followerGrowthData} color="#4338CA" height={80} />
                  </div>
                )}
              </div>

              {/* Post boost aggregate stats */}
              {(pbs.boosted_posts_active > 0 || pbs.total_boosted_impressions > 0) && (
                <div className="p-analytics-section">
                  <div className="p-analytics-section-title">
                    🚀 {t.postBoostStats || (t.postBoostStats)}
                  </div>
                  <div className="p-analytics-stat-row">
                    <StatCard label={t.activeBoosts} value={(pbs.boosted_posts_active ?? 0).toLocaleString()} color="#7C3AED" />
                    <StatCard label={t.adImpressions || (t.adImpressions)} value={(pbs.total_boosted_impressions ?? 0).toLocaleString()} color="#7C3AED" />
                  </div>
                </div>
              )}

              {/* Ad performance table */}
              <div className="p-analytics-section">
                <div className="p-analytics-section-title">
                  📢 {t.adManager || (t.adPerformance)}
                </div>
                {bs.adPerformance?.length > 0 ? (
                  <div style={{ overflowX: 'auto' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
                      <thead>
                        <tr style={{ borderBottom: '1px solid #E8E4DF' }}>
                          {[t.adTitle || 'Titel', t.adStatus || 'Status', t.adImpressions || 'Visninger', t.adClicks || 'Klik', t.adCTR || 'CTR', t.adReach || 'Rækkevidde', t.adSpent || 'Brugt', t.activeUntil].map(h => (
                            <th key={h} style={{ textAlign: 'left', padding: '6px 8px', fontWeight: 700, color: '#555', fontSize: 11 }}>{h}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {bs.adPerformance.map(ad => (
                          <tr key={ad.id} style={{ borderBottom: '1px solid #F0EDE8' }}>
                            <td style={{ padding: '6px 8px', color: '#1a1a1a', fontWeight: 600 }}>
                              {ad.isBoostedPost ? '🚀 ' : '📢 '}{(ad.title || '').slice(0, 30)}
                            </td>
                            <td style={{ padding: '6px 8px' }}>
                              <span style={{ fontSize: 11, fontWeight: 700, padding: '2px 7px', borderRadius: 8,
                                background: ad.is_active ? '#D1FAE5' : '#F3F4F6',
                                color: ad.is_active ? '#065F46' : '#374151' }}>
                                {ad.status}
                              </span>
                            </td>
                            <td style={{ padding: '6px 8px' }}>{ad.impressions.toLocaleString()}</td>
                            <td style={{ padding: '6px 8px' }}>{ad.clicks.toLocaleString()}</td>
                            <td style={{ padding: '6px 8px' }}>{ad.ctr.toFixed(1)}%</td>
                            <td style={{ padding: '6px 8px' }}>{ad.reach.toLocaleString()}</td>
                            <td style={{ padding: '6px 8px' }}>{formatPrice(ad.spent)}</td>
                            <td style={{ padding: '6px 8px', fontSize: 11, color: '#666' }}>
                              {ad.paid_until ? new Date(ad.paid_until).toLocaleDateString(getLocale(lang)) : '—'}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                ) : (
                  <div style={{ color: '#888', fontSize: 13, padding: '12px 0' }}>
                    {t.noAdsYet || (t.noAdsYet)}
                    {' — '}
                    <button
                      onClick={() => navigateTo('ads')}
                      style={{ background: 'none', border: 'none', color: '#2D6A4F', cursor: 'pointer', textDecoration: 'underline', fontSize: 13, padding: 0 }}
                    >
                      {t.goToAdManager || (t.goToAdManager)}
                    </button>
                  </div>
                )}
              </div>
            </>
          )
        })()}
      </div>
    </div>
  )
}

